problem:
A courier company is planning to open regional sorting hubs and assign delivery routes to hubs. Each candidate hub has a fixed opening cost and a maximum parcel volume capacity. Each delivery route has a minimum parcel demand that must be satisfied. The company can open at most a limited number of hubs. The objective is to minimize the total fixed hub opening costs plus the variable transportation costs from hubs to routes. Formulate an optimization model to decide which hubs to open and how many parcels to ship from each hub to each route, respecting capacity, demand, and hub limit constraints. All data are provided in data.json.

The following structured data files are provided:

### data.json
```json
{
  "Hubs": [
    "Hub1",
    "Hub2",
    "Hub3"
  ],
  "Routes": [
    "RouteA",
    "RouteB",
    "RouteC"
  ],
  "fixed_cost": {
    "Hub1": 5000,
    "Hub2": 7000,
    "Hub3": 6000
  },
  "transport_cost": {
    "Hub1": {
      "RouteA": 2,
      "RouteB": 3,
      "RouteC": 4
    },
    "Hub2": {
      "RouteA": 5,
      "RouteB": 1,
      "RouteC": 2
    },
    "Hub3": {
      "RouteA": 3,
      "RouteB": 4,
      "RouteC": 1
    }
  },
  "capacity": {
    "Hub1": 100,
    "Hub2": 150,
    "Hub3": 120
  },
  "demand": {
    "RouteA": 50,
    "RouteB": 60,
    "RouteC": 40
  },
  "max_hubs": 2
}
```

answer:
import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

offices = data["offices"]
segments = data["segments"]

fixed_cost = {o: c for o, c in zip(offices, data["fixed_cost"])}
var_cost = {(offices[i], segments[j]): data["var_cost"][i][j] for i in range(len(offices)) for j in range(len(segments))}
office_capacity = {o: c for o, c in zip(offices, data["office_capacity"])}
segment_min_budget = {s: b for s, b in zip(segments, data["segment_min_budget"])}
segment_max_budget = {s: b for s, b in zip(segments, data["segment_max_budget"])}
pair_capacity = {(offices[i], segments[j]): data["pair_capacity"][i][j] for i in range(len(offices)) for j in range(len(segments))}
max_active_offices = data["max_active_offices"]

model = gp.Model("optimization_problem")

y = model.addVars(offices, vtype=GRB.BINARY, name="y")
x = model.addVars(offices, segments, lb=0, vtype=GRB.CONTINUOUS, name="x")

model.setObjective(
    gp.quicksum(fixed_cost[o] * y[o] for o in offices) +
    gp.quicksum(var_cost[o, s] * x[o, s] for o in offices for s in segments),
    sense=GRB.MINIMIZE
)

for o in offices:
    model.addConstr(
        gp.quicksum(x[o, s] for s in segments) <= office_capacity[o],
        name=f"office_capacity_{o}"
    )

for s in segments:
    model.addConstr(
        gp.quicksum(x[o, s] for o in offices) >= segment_min_budget[s],
        name=f"segment_coverage_{s}"
    )
    model.addConstr(
        gp.quicksum(x[o, s] for o in offices) <= segment_max_budget[s],
        name=f"segment_upper_{s}"
    )

for o in offices:
    for s in segments:
        model.addConstr(
            x[o, s] <= pair_capacity[o, s] * y[o],
            name=f"pair_capacity_{o}_{s}"
        )

model.addConstr(
    gp.quicksum(y[o] for o in offices) <= max_active_offices,
    name="max_active_offices"
)

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

import gurobipy as gp
from gurobipy import GRB
import json
import os

with open("instance.json") as f:
    inst = json.load(f)

bigM = inst["bigM"]
num_plants = inst["num_plants"]
num_lines = inst["num_lines"]
num_alloys = inst["num_alloys"]
num_customers = inst["num_customers"]
num_materials = inst["num_materials"]
num_timeperiods = inst["num_timeperiods"]

PLANTS = range(1, num_plants + 1)
LINES = range(1, num_lines + 1)
ALLOYS = range(1, num_alloys + 1)
CUSTOMERS = range(1, num_customers + 1)
MATERIALS = range(1, num_materials + 1)
TIMEPERIODS = range(1, num_timeperiods + 1)

import pandas as pd

line_costs = pd.read_csv("data/line_costs.csv")
shipping_costs = pd.read_csv("data/shipping_costs.csv")
demand = pd.read_csv("data/demand.csv")
plant_params = pd.read_csv("data/plant_params.csv")
material_usage = pd.read_csv("data/material_usage.csv")
material_availability = pd.read_csv("data/material_availability.csv")

model = gp.Model("metal_fabrication")

flow = model.addVars(PLANTS, LINES, ALLOYS, CUSTOMERS, TIMEPERIODS, lb=0, vtype=GRB.CONTINUOUS, name="flow")
y = model.addVars(PLANTS, LINES, vtype=GRB.BINARY, name="y")
z = model.addVars(PLANTS, ALLOYS, lb=0, vtype=GRB.CONTINUOUS, name="z")
w = model.addVars(MATERIALS, TIMEPERIODS, lb=0, vtype=GRB.CONTINUOUS, name="w")
inv = model.addVars(MATERIALS, TIMEPERIODS, lb=0, vtype=GRB.CONTINUOUS, name="inv")

prod_cost_dict = {}
fixed_cost_dict = {}
capacity_dict = {}
alloy_line_flag_dict = {}
for _, row in line_costs.iterrows():
    p = int(row["plant_id"])
    l = int(row["line_id"])
    a = int(row["alloy_id"])
    prod_cost_dict[(p, l, a)] = row["prod_cost"]
    fixed_cost_dict[(p, l)] = row["fixed_cost"]
    capacity_dict[(p, l, a)] = row["capacity"]
    alloy_line_flag_dict[(l, a)] = row["alloy_line_flag"]

ship_cost_dict = {}
for _, row in shipping_costs.iterrows():
    p = int(row["plant_id"])
    c = int(row["customer_id"])
    ship_cost_dict[(p, c)] = row["ship_cost"]

demand_dict = {}
for _, row in demand.iterrows():
    c = int(row["customer_id"])
    a = int(row["alloy_id"])
    t = int(row["period"])
    demand_dict[(c, a, t)] = row["demand"]

plant_capacity_dict = {}
max_lines_dict = {}
min_production_dict = {}
for _, row in plant_params.iterrows():
    p = int(row["plant_id"])
    plant_capacity_dict[p] = row["plant_capacity"]
    max_lines_dict[p] = int(row["max_lines_per_plant"])
    a = int(row["alloy_id"])
    min_production_dict[(p, a)] = row["min_production"]

mat_consumption_dict = {}
for _, row in material_usage.iterrows():
    a = int(row["alloy_id"])
    m = int(row["material_id"])
    mat_consumption_dict[(a, m)] = row["mat_consumption"]

mat_availability_dict = {}
for _, row in material_availability.iterrows():
    m = int(row["material_id"])
    t = int(row["period"])
    mat_availability_dict[(m, t)] = row["mat_availability"]

obj = gp.QuadExpr()
for p in PLANTS:
    for l in LINES:
        for a in ALLOYS:
            for c in CUSTOMERS:
                for t in TIMEPERIODS:
                    obj += (prod_cost_dict.get((p, l, a), 0) + ship_cost_dict.get((p, c), 0)) * flow[p, l, a, c, t]
for p in PLANTS:
    for l in LINES:
        obj += fixed_cost_dict.get((p, l), 0) * y[p, l]
model.setObjective(obj, GRB.MINIMIZE)

for c in CUSTOMERS:
    for a in ALLOYS:
        for t in TIMEPERIODS:
            model.addConstr(gp.quicksum(flow[p, l, a, c, t] for p in PLANTS for l in LINES) == demand_dict.get((c, a, t), 0), name=f"demand_{c}_{a}_{t}")

for p in PLANTS:
    for l in LINES:
        for a in ALLOYS:
            for t in TIMEPERIODS:
                cap = capacity_dict.get((p, l, a), 0)
                if cap > 0:
                    model.addConstr(gp.quicksum(flow[p, l, a, c, t] for c in CUSTOMERS) <= cap * y[p, l], name=f"line_cap_{p}_{l}_{a}_{t}")

for p in PLANTS:
    for t in TIMEPERIODS:
        model.addConstr(gp.quicksum(flow[p, l, a, c, t] for l in LINES for a in ALLOYS for c in CUSTOMERS) <= plant_capacity_dict[p], name=f"plant_cap_{p}_{t}")

for l in LINES:
    model.addConstr(gp.quicksum(y[p, l] for p in PLANTS) <= 1, name=f"line_assign_{l}")

for p in PLANTS:
    for l in LINES:
        for a in ALLOYS:
            for c in CUSTOMERS:
                for t in TIMEPERIODS:
                    flag = alloy_line_flag_dict.get((l, a), 0)
                    if flag == 0:
                        model.addConstr(flow[p, l, a, c, t] <= 0, name=f"compat_{p}_{l}_{a}_{c}_{t}")

for p in PLANTS:
    for l in LINES:
        for a in ALLOYS:
            for c in CUSTOMERS:
                for t in TIMEPERIODS:
                    model.addConstr(flow[p, l, a, c, t] <= bigM * y[p, l], name=f"activation_{p}_{l}_{a}_{c}_{t}")

for m in MATERIALS:
    for t in TIMEPERIODS:
        if t == 1:
            model.addConstr(inv[m, t] == mat_availability_dict.get((m, t), 0) - w[m, t], name=f"mat_balance_{m}_{t}")
        else:
            model.addConstr(inv[m, t] == inv[m, t-1] + mat_availability_dict.get((m, t), 0) - w[m, t], name=f"mat_balance_{m}_{t}")

for m in MATERIALS:
    for t in TIMEPERIODS:
        model.addConstr(gp.quicksum(mat_consumption_dict.get((a, m), 0) * flow[p, l, a, c, t] for p in PLANTS for l in LINES for a in ALLOYS for c in CUSTOMERS) <= w[m, t], name=f"mat_cons_{m}_{t}")

for p in PLANTS:
    for a in ALLOYS:
        model.addConstr(gp.quicksum(flow[p, l, a, c, t] for l in LINES for c in CUSTOMERS for t in TIMEPERIODS) >= min_production_dict.get((p, a), 0), name=f"min_prod_{p}_{a}")

for p in PLANTS:
    model.addConstr(gp.quicksum(y[p, l] for l in LINES) <= max_lines_dict[p], name=f"max_lines_{p}")

for p in PLANTS:
    for a in ALLOYS:
        model.addConstr(gp.quicksum(flow[p, l, a, c, t] for l in LINES for c in CUSTOMERS for t in TIMEPERIODS) == z[p, a], name=f"z_def_{p}_{a}")

os.makedirs("output", exist_ok=True)
model.write("output/model.lp")

import gurobipy as gp
from gurobipy import GRB
import json
import csv

# Read instance.json
with open('instance.json', 'r') as f:
    instance = json.load(f)

truck_capacity = instance['truck_capacity']
max_trips_per_truck = instance['max_trips_per_truck']
max_drivers_shift = instance['max_drivers_shift']
shift_start = instance['shift_start']
shift_end = instance['shift_end']
min_rest_slots = instance['min_rest_slots']
max_work_slots_per_shift = instance['max_work_slots_per_shift']
slot_duration_minutes = instance['slot_duration_minutes']

# Read costs.csv
fuel_cost = {}
driver_wage = {}
with open('data/costs.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        d = row['depot_id']
        r = row['route_type']
        t = int(row['time_slot'])
        fuel_cost[(d, r)] = float(row['fuel_cost'])
        driver_wage[(d, r, t)] = float(row['driver_wage'])

# Read demand.csv
demand = {}
penalty_late = {}
with open('data/demand.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        z = row['zone_id']
        t = int(row['time_slot'])
        demand[(z, t)] = float(row['demand'])
        penalty_late[(z, t)] = float(row['penalty_late'])

# Read compatibility.csv
travel_time = {}
capacity_per_trip = {}
compatibility_flag = {}
with open('data/compatibility.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        d = row['depot_id']
        r = row['route_type']
        z = row['zone_id']
        travel_time[(d, r, z)] = int(row['travel_time'])
        capacity_per_trip[r] = float(row['capacity_per_trip'])
        compatibility_flag[(d, r, z)] = int(row['compatibility_flag'])

# Define sets
D = list(truck_capacity.keys())
Z = list(set(k[0] for k in demand.keys()))
R = list(set(k[1] for k in fuel_cost.keys()))
T = list(set(k[1] for k in demand.keys()))
S = list(shift_start.keys())

# Create model
model = gp.Model("trucking_scheduling")

# Decision variables
assign = model.addVars(D, R, T, vtype=GRB.INTEGER, lb=0, name="assign")
late = model.addVars(Z, T, vtype=GRB.CONTINUOUS, lb=0, name="late")
driver_used = model.addVars(D, S, T, vtype=GRB.INTEGER, lb=0, name="driver_used")
arrive = model.addVars(D, R, Z, T, vtype=GRB.CONTINUOUS, lb=0, name="arrive")
inventory = model.addVars(Z, T, vtype=GRB.CONTINUOUS, lb=0, name="inventory")

# Objective: minimize total operating cost
obj = gp.quicksum((fuel_cost[(d, r)] + driver_wage[(d, r, t)]) * assign[d, r, t] for d in D for r in R for t in T if (d, r, t) in driver_wage) + \
      gp.quicksum(penalty_late[(z, t)] * late[z, t] for z in Z for t in T)
model.setObjective(obj, GRB.MINIMIZE)

# Constraint 1: Truck capacity
for d in D:
    for t in T:
        model.addConstr(gp.quicksum(assign[d, r, t] for r in R) <= truck_capacity[d], name=f"truck_capacity_{d}_{t}")

# Constraint 2: Trip balance
for d in D:
    for t in T:
        if t > min(T):
            model.addConstr(gp.quicksum(assign[d, r, t] for r in R) <= gp.quicksum(assign[d, r, t-1] for r in R) + truck_capacity[d], name=f"trip_balance_{d}_{t}")

# Constraint 3: Driver shift capacity
for d in D:
    for s in S:
        for t in T:
            model.addConstr(driver_used[d, s, t] <= max_drivers_shift[d][s], name=f"driver_shift_capacity_{d}_{s}_{t}")

# Constraint 4: Driver shift time
for d in D:
    for s in S:
        for t in T:
            if t < shift_start[s] or t > shift_end[s]:
                model.addConstr(driver_used[d, s, t] == 0, name=f"driver_shift_time_{d}_{s}_{t}")

# Constraint 5: Driver rest
for d in D:
    for s in S:
        for t in T:
            if t + min_rest_slots - 1 <= max(T):
                for tau in range(min_rest_slots):
                    for s2 in S:
                        if s2 != s and t + tau <= max(T):
                            model.addConstr(driver_used[d, s, t] + driver_used[d, s2, t + tau] <= max_drivers_shift[d][s], name=f"driver_rest_{d}_{s}_{t}_{s2}_{tau}")

# Constraint 6: Trip-driver link
for d in D:
    for t in T:
        model.addConstr(gp.quicksum(assign[d, r, t] for r in R) <= gp.quicksum(driver_used[d, s, t] for s in S), name=f"trip_driver_link_{d}_{t}")

# Constraint 7: Arrival definition
for d in D:
    for r in R:
        for z in Z:
            for t in T:
                if (d, r, z) in travel_time and (d, r, z) in compatibility_flag:
                    tt = travel_time[(d, r, z)]
                    if t - tt >= min(T):
                        model.addConstr(arrive[d, r, z, t] == capacity_per_trip[r] * assign[d, r, t - tt] * compatibility_flag[(d, r, z)], name=f"arrival_definition_{d}_{r}_{z}_{t}")

# Constraint 8: Demand satisfaction
for z in Z:
    for t in T:
        if t > min(T):
            model.addConstr(inventory[z, t] == inventory[z, t-1] + gp.quicksum(arrive[d, r, z, t] for d in D for r in R if (d, r, z) in travel_time) - (demand[(z, t)] - late[z, t]), name=f"demand_satisfaction_{z}_{t}")
        else:
            model.addConstr(inventory[z, t] == gp.quicksum(arrive[d, r, z, t] for d in D for r in R if (d, r, z) in travel_time) - (demand[(z, t)] - late[z, t]), name=f"demand_satisfaction_{z}_{t}")

# Constraint 9: Late positive
for z in Z:
    for t in T:
        model.addConstr(late[z, t] <= demand[(z, t)], name=f"late_positive_{z}_{t}")

# Constraint 10: Inventory nonnegative (already enforced by lb=0)

# Constraint 11: Compatibility assign
for d in D:
    for r in R:
        for t in T:
            compat_sum = sum(compatibility_flag.get((d, r, z), 0) for z in Z)
            model.addConstr(assign[d, r, t] <= compat_sum * 1e6, name=f"compatibility_assign_{d}_{r}_{t}")

# Constraint 12: Max trips per truck
for d in D:
    for t in T:
        model.addConstr(gp.quicksum(assign[d, r, t] for r in R) <= truck_capacity[d] * max_trips_per_truck, name=f"max_trips_per_truck_{d}_{t}")

# Constraint 13: Shift work hours
for d in D:
    for s in S:
        for t in T:
            if t + max_work_slots_per_shift[s] - 1 <= max(T):
                model.addConstr(gp.quicksum(driver_used[d, s, tau] for tau in range(t, t + max_work_slots_per_shift[s])) <= max_work_slots_per_shift[s] * driver_used[d, s, t], name=f"shift_work_hours_{d}_{s}_{t}")

# Solve
model.optimize()

# Extract results
if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
else:
    print(f"Optimization status: {model.Status}")
    if model.Status == GRB.INFEASIBLE:
        print("optimal_value = INFEASIBLE")
    elif model.Status == GRB.UNBOUNDED:
        print("optimal_value = UNBOUNDED")
    else:
        print("optimal_value = ERROR")

import gurobipy as gp
from gurobipy import GRB
import json
import pandas as pd

# Read instance.json
with open('instance.json') as f:
    params = json.load(f)
big_M = params['big_M']
max_terminals = params['max_terminals']
penalty_shortfall = params['penalty_shortfall']

# Read CSV files
supply_df = pd.read_csv('data/supply_zones.csv')
demand_df = pd.read_csv('data/demand_regions.csv')
terminals_df = pd.read_csv('data/terminals.csv')
lanes_df = pd.read_csv('data/lanes.csv')
lane_commodity_df = pd.read_csv('data/lane_commodity.csv')

# Create model
model = gp.Model('multimodal_freight')

# Sets
supply_zones = supply_df['supply_id'].unique().tolist()
demand_regions = demand_df['demand_id'].unique().tolist()
terminals = terminals_df['terminal_id'].unique().tolist()
commodities = supply_df['commodity_id'].unique().tolist()
lanes = lanes_df['lane_id'].unique().tolist()

# Parameters
supply_avail = {(row['supply_id'], row['commodity_id']): row['supply_avail'] for _, row in supply_df.iterrows()}
demand_req = {(row['demand_id'], row['commodity_id']): row['demand_req'] for _, row in demand_df.iterrows()}
fixed_cost = {row['terminal_id']: row['fixed_cost'] for _, row in terminals_df.iterrows()}
handling_cost = {row['terminal_id']: row['handling_cost'] for _, row in terminals_df.iterrows()}
handling_capacity = {row['terminal_id']: row['handling_capacity'] for _, row in terminals_df.iterrows()}
min_throughput = {row['terminal_id']: row['min_throughput'] for _, row in terminals_df.iterrows()}
transport_cost = {row['lane_id']: row['transport_cost'] for _, row in lanes_df.iterrows()}
lane_capacity = {row['lane_id']: row['lane_capacity'] for _, row in lanes_df.iterrows()}
source_node = {row['lane_id']: row['source_node'] for _, row in lanes_df.iterrows()}
target_node = {row['lane_id']: row['target_node'] for _, row in lanes_df.iterrows()}
terminal_of_lane = {row['lane_id']: row['terminal_of_lane'] for _, row in lanes_df.iterrows()}
lane_type = {row['lane_id']: row['lane_type'] for _, row in lanes_df.iterrows()}
commodity_on_lane = {(row['lane_id'], row['commodity_id']): row['commodity_on_lane'] for _, row in lane_commodity_df.iterrows()}

# Decision variables
f = model.addVars(lanes, commodities, lb=0, vtype=GRB.CONTINUOUS, name='f')
h = model.addVars(terminals, commodities, lb=0, vtype=GRB.CONTINUOUS, name='h')
y = model.addVars(terminals, vtype=GRB.BINARY, name='y')
shortfall = model.addVars(demand_regions, commodities, lb=0, vtype=GRB.CONTINUOUS, name='shortfall')
slack = model.addVars(supply_zones, commodities, lb=0, vtype=GRB.CONTINUOUS, name='slack')

# Objective: minimize total cost
obj = gp.quicksum(fixed_cost[t] * y[t] + handling_cost[t] * gp.quicksum(h[t, c] for c in commodities) for t in terminals)
obj += gp.quicksum(transport_cost[l] * gp.quicksum(f[l, c] for c in commodities) for l in lanes)
obj += penalty_shortfall * gp.quicksum(shortfall[d, c] for d in demand_regions for c in commodities)
model.setObjective(obj, GRB.MINIMIZE)

# Constraints
# 1. Supply balance
for (s, c), avail in supply_avail.items():
    outflow = gp.quicksum(f[l, c] for l in lanes if source_node[l] == s)
    model.addConstr(outflow + slack[s, c] == avail, name=f'supply_balance_{s}_{c}')

# 2. Demand balance
for d in demand_regions:
    for c in commodities:
        inflow = gp.quicksum(f[l, c] for l in lanes if target_node[l] == d)
        model.addConstr(inflow + shortfall[d, c] == demand_req.get((d, c), 0), name=f'demand_balance_{d}_{c}')

# 3. Flow conservation inbound
for t in terminals:
    for c in commodities:
        inbound = gp.quicksum(f[l, c] for l in lanes if target_node[l] == t and lane_type[l] == 'inbound')
        model.addConstr(inbound == h[t, c], name=f'flow_conservation_inbound_{t}_{c}')

# 4. Flow conservation outbound
for t in terminals:
    for c in commodities:
        outbound = gp.quicksum(f[l, c] for l in lanes if source_node[l] == t and lane_type[l] == 'outbound')
        model.addConstr(h[t, c] == outbound, name=f'flow_conservation_outbound_{t}_{c}')

# 5. Handling capacity
for t in terminals:
    model.addConstr(gp.quicksum(h[t, c] for c in commodities) <= handling_capacity[t] * y[t], name=f'handling_capacity_{t}')

# 6. Minimum throughput
for t in terminals:
    model.addConstr(gp.quicksum(h[t, c] for c in commodities) >= min_throughput[t] * y[t], name=f'min_throughput_{t}')

# 7. Lane capacity
for l in lanes:
    model.addConstr(gp.quicksum(f[l, c] for c in commodities) <= lane_capacity[l], name=f'lane_capacity_{l}')

# 8. Commodity allowed
for l in lanes:
    for c in commodities:
        model.addConstr(f[l, c] <= big_M * commodity_on_lane.get((l, c), 0), name=f'commodity_allowed_{l}_{c}')

# 9. Activation link inbound
for l in lanes:
    if lane_type[l] == 'inbound':
        model.addConstr(gp.quicksum(f[l, c] for c in commodities) <= big_M * y[terminal_of_lane[l]], name=f'activation_link_inbound_{l}')

# 10. Activation link outbound
for l in lanes:
    if lane_type[l] == 'outbound':
        model.addConstr(gp.quicksum(f[l, c] for c in commodities) <= big_M * y[terminal_of_lane[l]], name=f'activation_link_outbound_{l}')

# 11. Max terminals
model.addConstr(gp.quicksum(y[t] for t in terminals) <= max_terminals, name='max_terminals')

# 12. Shortfall upper bound
for d in demand_regions:
    for c in commodities:
        model.addConstr(shortfall[d, c] <= demand_req.get((d, c), 0), name=f'shortfall_upper_{d}_{c}')

# Solve
model.optimize()

# Print results
if model.Status == GRB.OPTIMAL:
    print(f'optimal_value = {model.ObjVal}')
else:
    print(f'Optimization status: {model.Status}')
    if model.Status == GRB.INFEASIBLE:
        print('optimal_value = INFEASIBLE')
    elif model.Status == GRB.UNBOUNDED:
        print('optimal_value = UNBOUNDED')
    else:
        print('optimal_value = ERROR')

import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

T = data["T"]
num_depots = data["num_depots"]
num_vehicles = data["num_vehicles"]
demand = data["demand"]
initial_inventory = data["initial_inventory"]
holding_cost = data["holding_cost"]
ordering_cost = data["ordering_cost"]
penalty_cost = data["penalty_cost"]
depot_capacity = data["depot_capacity"]
ordering_limit = data["ordering_limit"]
vehicle_cost = data["vehicle_cost"]
vehicle_capacity = data["vehicle_capacity"]
vehicle_limit = data["vehicle_limit"]
transport_cost = data["transport_cost"]
decay_factor = data["decay_factor"]

Depots = range(num_depots)
Periods = range(T)
Vehicles = range(num_vehicles)

model = gp.Model("inventory_optimization")

INV = model.addVars(Depots, Periods, vtype=GRB.INTEGER, lb=0, name="INV")
ORD = model.addVars(Depots, Periods, vtype=GRB.INTEGER, lb=0, name="ORD")
SLACK = model.addVars(Depots, Periods, vtype=GRB.CONTINUOUS, lb=0, name="SLACK")
TRANS = model.addVars(Vehicles, Depots, Periods, vtype=GRB.INTEGER, lb=0, name="TRANS")

model.setObjective(
    gp.quicksum(holding_cost[d] * INV[d, t] + ordering_cost[d] * ORD[d, t] + penalty_cost[d] * SLACK[d, t]
                for d in Depots for t in Periods)
    + gp.quicksum(vehicle_cost[v] * TRANS[v, d, t] for v in Vehicles for d in Depots for t in Periods),
    GRB.MINIMIZE
)

for d in Depots:
    model.addConstr(INV[d, 0] == initial_inventory[d], name=f"INIT_INV_{d}")

for d in Depots:
    for t in Periods:
        model.addConstr(INV[d, t] + ORD[d, t] + SLACK[d, t] >= demand[d][t], name=f"DEMAND_{d}_{t}")

for d in Depots:
    for t in range(1, T):
        model.addConstr(INV[d, t] == decay_factor * INV[d, t-1] + ORD[d, t-1] - demand[d][t] + SLACK[d, t],
                        name=f"INV_BALANCE_{d}_{t}")

for d in Depots:
    for t in Periods:
        model.addConstr(INV[d, t] <= depot_capacity[d], name=f"CAPACITY_{d}_{t}")

for d in Depots:
    for t in Periods:
        model.addConstr(ORD[d, t] <= ordering_limit[d], name=f"ORDER_LIMIT_{d}_{t}")

for d in Depots:
    for t in Periods:
        model.addConstr(ORD[d, t] <= gp.quicksum(vehicle_capacity[v] * TRANS[v, d, t] for v in Vehicles),
                        name=f"VEHICLE_CAPACITY_{d}_{t}")

for v in Vehicles:
    for t in Periods:
        model.addConstr(gp.quicksum(TRANS[v, d, t] for d in Depots) <= vehicle_limit[v],
                        name=f"VEHICLE_LIMIT_{v}_{t}")

for d in Depots:
    for t in Periods:
        model.addConstr(SLACK[d, t] <= 0.2 * demand[d][t], name=f"SLACK_BOUND_{d}_{t}")

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

