import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

plants = [p["id"] for p in data["Plants"]]
zones = [z["id"] for z in data["Zones"]]
pipes = data["Pipes"]

plant_capacity = {p["id"]: p["capacity"] for p in data["Plants"]}
zone_demand = {z["id"]: z["demand"] for z in data["Zones"]}

revenue = {}
for i, p in enumerate(plants):
    for j, z in enumerate(zones):
        revenue[p, z] = data["revenue"][i][j]

max_pressure_drop = {}
for i, p in enumerate(plants):
    max_pressure_drop[p] = data["max_pressure_drop"][i]

pipe_capacity = {}
pipe_from_plant = {}
pipe_to_zone = {}
pressure_drop_coeff = {}
for k, pipe in enumerate(pipes):
    pid = pipe["id"]
    pipe_capacity[pid] = pipe["capacity"]
    pipe_from_plant[pid] = pipe["from_plant"]
    pipe_to_zone[pid] = pipe["to_zone"]
    pressure_drop_coeff[pid] = pipe["pressure_drop_coeff"]

model = gp.Model("district_heating")

flow = model.addVars(plants, zones, lb=0, name="flow")
plant_output = model.addVars(plants, lb=0, name="plant_output")

model.setObjective(gp.quicksum(revenue[p, z] * flow[p, z] for p in plants for z in zones), GRB.MAXIMIZE)

for p in plants:
    model.addConstr(plant_output[p] <= plant_capacity[p], name=f"PlantCapacity_{p}")
    model.addConstr(plant_output[p] == gp.quicksum(flow[p, z] for z in zones), name=f"PlantOutputDef_{p}")

for z in zones:
    model.addConstr(gp.quicksum(flow[p, z] for p in plants) >= zone_demand[z], name=f"ZoneDemand_{z}")

for pipe in pipes:
    pid = pipe["id"]
    p = pipe["from_plant"]
    z = pipe["to_zone"]
    model.addConstr(flow[p, z] <= pipe_capacity[pid], name=f"PipeCapacity_{pid}")

for p in plants:
    model.addConstr(
        gp.quicksum(pressure_drop_coeff[pid] * flow[pipe_from_plant[pid], pipe_to_zone[pid]]
                    for pid in pipe_from_plant if pipe_from_plant[pid] == p) <= max_pressure_drop[p],
        name=f"PressureDrop_{p}"
    )

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

import gurobipy as gp
from gurobipy import GRB
import json
import pandas as pd

# Read instance.json
with open("instance.json", "r") as f:
    params = json.load(f)
regular_hours = params["regular_hours"]
overtime_hours = params["overtime_hours"]
penalty = params["penalty"]
min_rest = params["min_rest"]

# Read CSV files
paramedics_df = pd.read_csv("data/paramedics.csv")
stations_df = pd.read_csv("data/stations.csv")
time_slots_df = pd.read_csv("data/time_slots.csv")
skills_df = pd.read_csv("data/skills.csv")
demand_df = pd.read_csv("data/demand.csv")
skill_requirements_df = pd.read_csv("data/skill_requirements.csv")
paramedic_skills_df = pd.read_csv("data/paramedic_skills.csv")

# Sets
P = paramedics_df["paramedic_id"].tolist()
S = stations_df["station_id"].tolist()
T = time_slots_df["time_slot_id"].tolist()
K = skills_df["skill_id"].tolist()

# Parameters
wage = dict(zip(paramedics_df["paramedic_id"], paramedics_df["wage"]))
overtime_rate = dict(zip(paramedics_df["paramedic_id"], paramedics_df["overtime_rate"]))
max_shifts = dict(zip(paramedics_df["paramedic_id"], paramedics_df["max_shifts"]))
max_overtime = dict(zip(paramedics_df["paramedic_id"], paramedics_df["max_overtime"]))

demand = {}
for _, row in demand_df.iterrows():
    demand[(row["time_slot_id"], row["station_id"])] = row["demand"]

skill_required = {}
for _, row in skill_requirements_df.iterrows():
    skill_required[(row["time_slot_id"], row["station_id"], row["skill_id"])] = row["skill_required"]

skill_level = {}
for _, row in paramedic_skills_df.iterrows():
    skill_level[(row["paramedic_id"], row["skill_id"])] = row["skill_level"]

# Model
model = gp.Model("paramedic_scheduling")

# Decision variables
x = model.addVars(P, T, S, vtype=GRB.BINARY, name="x")
y = model.addVars(P, T, S, vtype=GRB.CONTINUOUS, lb=0, name="y")
u = model.addVars(T, S, vtype=GRB.CONTINUOUS, lb=0, name="u")

# Objective: minimize total cost
obj = gp.QuadExpr()
for p in P:
    for t in T:
        for s in S:
            obj += wage[p] * x[p, t, s] + overtime_rate[p] * y[p, t, s]
for t in T:
    for s in S:
        obj += penalty * u[t, s]
model.setObjective(obj, GRB.MINIMIZE)

# Constraints
# Demand coverage
for t in T:
    for s in S:
        model.addConstr(gp.quicksum(x[p, t, s] for p in P) + u[t, s] >= demand.get((t, s), 0), name=f"demand_{t}_{s}")

# Skill coverage
for t in T:
    for s in S:
        for k in K:
            lhs = gp.quicksum(skill_level.get((p, k), 0) * x[p, t, s] for p in P)
            rhs = skill_required.get((t, s, k), 0)
            model.addConstr(lhs >= rhs, name=f"skill_{t}_{s}_{k}")

# Max shifts per paramedic
for p in P:
    model.addConstr(gp.quicksum(x[p, t, s] for t in T for s in S) <= max_shifts[p], name=f"max_shifts_{p}")

# Overtime limit per paramedic
for p in P:
    model.addConstr(gp.quicksum(y[p, t, s] for t in T for s in S) <= max_overtime[p], name=f"overtime_limit_{p}")

# Overtime binding: y <= overtime_hours * x
for p in P:
    for t in T:
        for s in S:
            model.addConstr(y[p, t, s] <= overtime_hours * x[p, t, s], name=f"overtime_bind_{p}_{t}_{s}")

# Rest constraint: regular_hours * x + y <= min_rest * 24 for each paramedic and time slot
for p in P:
    for t in T:
        model.addConstr(gp.quicksum(regular_hours * x[p, t, s] + y[p, t, s] for s in S) <= min_rest * 24, name=f"rest_{p}_{t}")

# Single station per time slot
for p in P:
    for t in T:
        model.addConstr(gp.quicksum(x[p, t, s] for s in S) <= 1, name=f"single_station_{p}_{t}")

# Solve
model.optimize()

# Print results
if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
else:
    print(f"Optimization status: {model.Status}")
    if model.Status == GRB.INFEASIBLE:
        print("optimal_value = INFEASIBLE")
    elif model.Status == GRB.UNBOUNDED:
        print("optimal_value = UNBOUNDED")
    else:
        print("optimal_value = ERROR")

