import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

depots = [d["depot_id"] for d in data["depots"]]
kits = [k["kit_id"] for k in data["kits"]]
periods = sorted(set(d["period"] for d in data["demand"]))

holding_cost = {(d["depot_id"], k["kit_id"]): k["holding_cost"] for d in data["depots"] for k in data["kits"]}
init_inv = {(i["depot_id"], i["kit_id"]): i["init_qty"] for i in data["initial_inventory"]}
demand = {(d["kit_id"], d["period"]): d["demand_qty"] for d in data["demand"]}
max_order = {(m["kit_id"], m["period"]): m["max_qty"] for m in data["max_order"]}
capacity = {d["depot_id"]: d["capacity"] for d in data["depots"]}
shelf_life = {k["kit_id"]: k["shelf_life"] for k in data["kits"]}

model = gp.Model("medical_supply_chain")

I = model.addVars(depots, kits, periods, lb=0, vtype=GRB.CONTINUOUS, name="I")
O = model.addVars(kits, periods, lb=0, vtype=GRB.CONTINUOUS, name="O")

model.setObjective(
    gp.quicksum(holding_cost[d, k] * I[d, k, t] for d in depots for k in kits for t in periods),
    GRB.MINIMIZE
)

for d in depots:
    for k in kits:
        for t in periods:
            if t == 1:
                model.addConstr(
                    I[d, k, t] == init_inv.get((d, k), 0) + O[k, t] / len(depots) - demand.get((k, t), 0) / len(depots),
                    name=f"inv_balance_{d}_{k}_{t}"
                )
            else:
                model.addConstr(
                    I[d, k, t] == I[d, k, t-1] + O[k, t] / len(depots) - demand.get((k, t), 0) / len(depots),
                    name=f"inv_balance_{d}_{k}_{t}"
                )

for d in depots:
    for t in periods:
        model.addConstr(
            gp.quicksum(I[d, k, t] for k in kits) <= capacity[d],
            name=f"capacity_{d}_{t}"
        )

for k in kits:
    for t in periods:
        model.addConstr(
            O[k, t] <= max_order.get((k, t), 0),
            name=f"order_limit_{k}_{t}"
        )

for k in kits:
    for t in periods:
        model.addConstr(
            gp.quicksum(I[d, k, t] for d in depots) >= demand.get((k, t), 0),
            name=f"demand_satisfaction_{k}_{t}"
        )

for k in kits:
    for t in periods:
        for d in depots:
            model.addConstr(
                I[d, k, t] <= shelf_life[k] * max_order.get((k, t), 0),
                name=f"shelf_life_limit_{d}_{k}_{t}"
            )

model.write("model.lp")

