from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

additives = data["additives"]
chemicals = data["chemicals"]
blend_ratios = data["blend_ratios"]

A = [a["name"] for a in additives]
C = [c["name"] for c in chemicals]

profit = {a["name"]: a["profit"] for a in additives}
octane_requirement = {a["name"]: a["octane_requirement"] for a in additives}
sulfur_limit = {a["name"]: a["sulfur_limit"] for a in additives}

octane_contribution = {c["name"]: c["octane_contribution"] for c in chemicals}
sulfur_content = {c["name"]: c["sulfur_content"] for c in chemicals}
availability = {c["name"]: c["availability"] for c in chemicals}

blend_ratio = {}
for br in blend_ratios:
    a = br["additive"]
    c = br["chemical"]
    blend_ratio[(a, c)] = br["ratio"]

model = gp.Model("fuel_additive_blending")

x = model.addVars(A, vtype=GRB.INTEGER, lb=0, name="x")

model.setObjective(gp.quicksum(profit[a] * x[a] for a in A), GRB.MAXIMIZE)

for c in C:
    model.addConstr(
        gp.quicksum(blend_ratio[(a, c)] * x[a] for a in A) <= availability[c],
        name=f"chemical_availability_{c}"
    )

for a in A:
    total_ratio = gp.quicksum(blend_ratio[(a, c)] for c in C)
    model.addConstr(
        gp.quicksum(octane_contribution[c] * blend_ratio[(a, c)] * x[a] for c in C)
        >= octane_requirement[a] * total_ratio * x[a],
        name=f"octane_min_{a}"
    )

for a in A:
    total_ratio = gp.quicksum(blend_ratio[(a, c)] for c in C)
    model.addConstr(
        gp.quicksum(sulfur_content[c] * blend_ratio[(a, c)] * x[a] for c in C)
        <= sulfur_limit[a] * total_ratio * x[a],
        name=f"sulfur_max_{a}"
    )

model.write("model.lp")

