import gurobipy as gp
from gurobipy import GRB
import json

with open('data.json', 'r') as f:
    data = json.load(f)

products = [p['id'] for p in data['products']]
clients = [c['id'] for c in data['clients']]
periods = [t['id'] for t in data['periods']]

fixed_cost = {p['id']: p['fixed_cost'] for p in data['products']}
var_cost = {(v['product_id'], v['client_id']): v['cost'] for v in data['var_cost']}
return_target = {(r['client_id'], r['period_id']): r['target'] for r in data['return_target']}
risk_limit = {(r['product_id'], r['period_id']): r['limit'] for r in data['risk_limit']}
diversity_min = {c['id']: c['diversity_min'] for c in data['clients']}
preferred = {(p['product_id'], p['client_id']): p['flag'] for p in data['preferred']}
bigM = data['bigM']
min_products = data['min_products']

model = gp.Model('investment_selection')

select = model.addVars(products, vtype=GRB.BINARY, name='select')
allocate = model.addVars(products, clients, periods, lb=0, vtype=GRB.CONTINUOUS, name='allocate')

model.setObjective(
    gp.quicksum(fixed_cost[p] * select[p] for p in products) +
    gp.quicksum(var_cost[p, c] * allocate[p, c, t] for p in products for c in clients for t in periods),
    GRB.MINIMIZE
)

for c in clients:
    for t in periods:
        model.addConstr(
            gp.quicksum(allocate[p, c, t] for p in products) >= return_target[c, t],
            name=f'return_satisfaction_{c}_{t}'
        )

for p in products:
    for t in periods:
        model.addConstr(
            gp.quicksum(allocate[p, c, t] for c in clients) <= risk_limit[p, t],
            name=f'risk_limit_{p}_{t}'
        )

for c in clients:
    for t in periods:
        model.addConstr(
            gp.quicksum(preferred[p, c] * allocate[p, c, t] for p in products) >= diversity_min[c] * return_target[c, t],
            name=f'diversity_requirement_{c}_{t}'
        )

for p in products:
    for c in clients:
        for t in periods:
            model.addConstr(
                allocate[p, c, t] <= bigM * select[p],
                name=f'allocate_linking_{p}_{c}_{t}'
            )

model.addConstr(
    gp.quicksum(select[p] for p in products) >= min_products,
    name='min_products_selected'
)

model.write('model.lp')

import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

FACTORIES = data["FACTORIES"]
DEPOTS = data["DEPOTS"]
CUSTOMERS = data["CUSTOMERS"]
PRODUCTS = data["PRODUCTS"]

supply = data["supply"]
demand = data["demand"]
in_cost = data["in_cost"]
out_cost = data["out_cost"]
depot_capacity = data["depot_capacity"]
route_cap = data["route_cap"]
depot_handling_cost = data["depot_handling_cost"]

model = gp.Model("multi_echelon_distribution")

x = {}
for i, f in enumerate(FACTORIES):
    for j, d in enumerate(DEPOTS):
        for k, p in enumerate(PRODUCTS):
            x[f, d, p] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"x_{f}_{d}_{p}")

y = {}
for j, d in enumerate(DEPOTS):
    for c_idx, c in enumerate(CUSTOMERS):
        for k, p in enumerate(PRODUCTS):
            y[d, c, p] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"y_{d}_{c}_{p}")

model.setObjective(
    gp.quicksum(in_cost[i][j][k] * x[f, d, p]
                for i, f in enumerate(FACTORIES)
                for j, d in enumerate(DEPOTS)
                for k, p in enumerate(PRODUCTS)) +
    gp.quicksum(out_cost[j][c_idx][k] * y[d, c, p]
                for j, d in enumerate(DEPOTS)
                for c_idx, c in enumerate(CUSTOMERS)
                for k, p in enumerate(PRODUCTS)),
    GRB.MINIMIZE
)

for i, f in enumerate(FACTORIES):
    for k, p in enumerate(PRODUCTS):
        model.addConstr(
            gp.quicksum(x[f, d, p] for j, d in enumerate(DEPOTS)) <= supply[i][k],
            name=f"supply_limit_{f}_{p}"
        )

for c_idx, c in enumerate(CUSTOMERS):
    for k, p in enumerate(PRODUCTS):
        model.addConstr(
            gp.quicksum(y[d, c, p] for j, d in enumerate(DEPOTS)) >= demand[c_idx][k],
            name=f"demand_satisfaction_{c}_{p}"
        )

for j, d in enumerate(DEPOTS):
    for k, p in enumerate(PRODUCTS):
        model.addConstr(
            gp.quicksum(x[f, d, p] for i, f in enumerate(FACTORIES)) ==
            gp.quicksum(y[d, c, p] for c_idx, c in enumerate(CUSTOMERS)),
            name=f"depot_balance_{d}_{p}"
        )

for j, d in enumerate(DEPOTS):
    model.addConstr(
        gp.quicksum(x[f, d, p] for i, f in enumerate(FACTORIES) for k, p in enumerate(PRODUCTS)) <= depot_capacity[j],
        name=f"depot_throughput_{d}"
    )

for i, f in enumerate(FACTORIES):
    for j, d in enumerate(DEPOTS):
        model.addConstr(
            gp.quicksum(x[f, d, p] for k, p in enumerate(PRODUCTS)) <= route_cap[i][j],
            name=f"route_capacity_{f}_{d}"
        )

model.write("model.lp")

import gurobipy as gp
from gurobipy import GRB
import json
import pandas as pd

with open("instance.json") as f:
    instance = json.load(f)

min_rest_hours = instance["min_rest_hours"]
max_consecutive_night_shifts = instance["max_consecutive_night_shifts"]
max_weekends_worked = instance["max_weekends_worked"]

preferences = pd.read_csv("data/preferences.csv")
coverage = pd.read_csv("data/coverage.csv")
shift_skills = pd.read_csv("data/shift_skills.csv")
nurse_skills = pd.read_csv("data/nurse_skills.csv")
shift_seniority = pd.read_csv("data/shift_seniority.csv")
nurse_seniority = pd.read_csv("data/nurse_seniority.csv")
nurse_limits = pd.read_csv("data/nurse_limits.csv")
shift_info = pd.read_csv("data/shift_info.csv")
day_info = pd.read_csv("data/day_info.csv")

nurses = sorted(preferences["nurse_id"].unique())
days = sorted(preferences["day_id"].unique())
shifts = sorted(preferences["shift_id"].unique())
skills = sorted(nurse_skills["skill_id"].unique())
seniorities = sorted(nurse_seniority["seniority_id"].unique())
weeks = sorted(day_info["week_id"].unique())

pref_dict = {}
for _, row in preferences.iterrows():
    pref_dict[(row["nurse_id"], row["day_id"], row["shift_id"])] = row["preference"]

min_nurses_dict = {}
max_nurses_dict = {}
for _, row in coverage.iterrows():
    min_nurses_dict[(row["day_id"], row["shift_id"])] = row["min_nurses"]
    max_nurses_dict[(row["day_id"], row["shift_id"])] = row["max_nurses"]

skill_need_dict = {}
for _, row in shift_skills.iterrows():
    skill_need_dict[(row["shift_id"], row["skill_id"])] = row["required"]

nurse_skill_dict = {}
for _, row in nurse_skills.iterrows():
    nurse_skill_dict[(row["nurse_id"], row["skill_id"])] = row["has_skill"]

seniority_need_dict = {}
for _, row in shift_seniority.iterrows():
    seniority_need_dict[(row["shift_id"], row["seniority_id"])] = row["required"]

nurse_seniority_dict = {}
for _, row in nurse_seniority.iterrows():
    nurse_seniority_dict[(row["nurse_id"], row["seniority_id"])] = row["has_seniority"]

max_shifts_per_week_dict = {}
max_hours_per_week_dict = {}
for _, row in nurse_limits.iterrows():
    max_shifts_per_week_dict[row["nurse_id"]] = row["max_shifts_per_week"]
    max_hours_per_week_dict[row["nurse_id"]] = row["max_hours_per_week"]

shift_duration_dict = {}
shift_time_block_dict = {}
for _, row in shift_info.iterrows():
    shift_duration_dict[row["shift_id"]] = row["duration_hours"]
    shift_time_block_dict[row["shift_id"]] = row["time_block_id"]

day_week_dict = {}
day_is_weekend_dict = {}
for _, row in day_info.iterrows():
    day_week_dict[row["day_id"]] = row["week_id"]
    day_is_weekend_dict[row["day_id"]] = row["is_weekend"]

model = gp.Model("nurse_scheduling")

assign = model.addVars(nurses, days, shifts, vtype=GRB.BINARY, name="assign")
night_assign = model.addVars(nurses, days, vtype=GRB.BINARY, name="night_assign")
weekend_work = model.addVars(nurses, weeks, vtype=GRB.BINARY, name="weekend_work")
rest_violation = model.addVars(nurses, days, vtype=GRB.BINARY, name="rest_violation")
skill_gap = model.addVars(nurses, days, shifts, skills, vtype=GRB.BINARY, name="skill_gap")

# Objective: maximize total preference minus penalties for skill gaps and rest violations
penalty_skill_gap = 100
penalty_rest_violation = 50
obj = gp.quicksum(pref_dict[(n, d, s)] * assign[n, d, s] for n in nurses for d in days for s in shifts if (n, d, s) in pref_dict)
obj -= penalty_skill_gap * gp.quicksum(skill_gap[n, d, s, k] for n in nurses for d in days for s in shifts for k in skills)
obj -= penalty_rest_violation * gp.quicksum(rest_violation[n, d] for n in nurses for d in days)
model.setObjective(obj, GRB.MAXIMIZE)

# Coverage constraints
for d in days:
    for s in shifts:
        if (d, s) in min_nurses_dict:
            model.addConstr(gp.quicksum(assign[n, d, s] for n in nurses) >= min_nurses_dict[(d, s)], name=f"min_coverage_{d}_{s}")
        if (d, s) in max_nurses_dict:
            model.addConstr(gp.quicksum(assign[n, d, s] for n in nurses) <= max_nurses_dict[(d, s)], name=f"max_coverage_{d}_{s}")

# One shift per day
for n in nurses:
    for d in days:
        model.addConstr(gp.quicksum(assign[n, d, s] for s in shifts) <= 1, name=f"one_shift_{n}_{d}")

# Weekly shift limit
for n in nurses:
    for w in weeks:
        days_in_week = [d for d in days if day_week_dict[d] == w]
        model.addConstr(gp.quicksum(assign[n, d, s] for d in days_in_week for s in shifts) <= max_shifts_per_week_dict[n], name=f"max_weekly_shifts_{n}_{w}")

# Weekly hour limit
for n in nurses:
    for w in weeks:
        days_in_week = [d for d in days if day_week_dict[d] == w]
        model.addConstr(gp.quicksum(shift_duration_dict[s] * assign[n, d, s] for d in days_in_week for s in shifts) <= max_hours_per_week_dict[n], name=f"max_weekly_hours_{n}_{w}")

# Skill requirement with skill_gap
for n in nurses:
    for d in days:
        for s in shifts:
            for k in skills:
                if (s, k) in skill_need_dict and skill_need_dict[(s, k)] == 1:
                    has_skill = nurse_skill_dict.get((n, k), 0)
                    model.addConstr(assign[n, d, s] <= has_skill + skill_gap[n, d, s, k], name=f"skill_req_{n}_{d}_{s}_{k}")

# Seniority requirement
for n in nurses:
    for d in days:
        for s in shifts:
            for l in seniorities:
                if (s, l) in seniority_need_dict and seniority_need_dict[(s, l)] == 1:
                    has_seniority = nurse_seniority_dict.get((n, l), 0)
                    model.addConstr(assign[n, d, s] <= has_seniority, name=f"seniority_req_{n}_{d}_{s}_{l}")

# Night shift definition
for n in nurses:
    for d in days:
        night_shifts = [s for s in shifts if shift_time_block_dict[s] == 2]
        model.addConstr(night_assign[n, d] == gp.quicksum(assign[n, d, s] for s in night_shifts), name=f"night_def_{n}_{d}")

# Consecutive night shifts
for n in nurses:
    for d in days:
        if d + max_consecutive_night_shifts <= max(days):
            model.addConstr(gp.quicksum(night_assign[n, d + t] for t in range(max_consecutive_night_shifts + 1)) <= max_consecutive_night_shifts, name=f"max_consec_night_{n}_{d}")

# Rest period
for n in nurses:
    for d in days:
        if d + 1 in days:
            model.addConstr(gp.quicksum(assign[n, d, s] for s in shifts) + gp.quicksum(assign[n, d + 1, s] for s in shifts) <= 1 + rest_violation[n, d], name=f"rest_period_{n}_{d}")

# Weekend work definition
for n in nurses:
    for w in weeks:
        weekend_days = [d for d in days if day_week_dict[d] == w and day_is_weekend_dict[d] == 1]
        if weekend_days:
            model.addConstr(weekend_work[n, w] >= gp.quicksum(assign[n, d, s] for d in weekend_days for s in shifts) / (len(shifts) * len(weekend_days)), name=f"weekend_def_{n}_{w}")

# Weekend limit
for n in nurses:
    model.addConstr(gp.quicksum(weekend_work[n, w] for w in weeks) <= max_weekends_worked, name=f"max_weekends_{n}")

import os
os.makedirs("output", exist_ok=True)
model.write("output/model.lp")

