import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

W_max = data["W_max"]
num_depots = data["num_depots"]
demand = data["demand"]
init_inv = data["init_inv"]
hold_cost = data["hold_cost"]
order_cost = data["order_cost"]
spoil_cost = data["spoil_cost"]
order_limit = data["order_limit"]
inv_min = data["inv_min"]
inv_max = data["inv_max"]

D = range(num_depots)
W = range(1, W_max + 1)

model = gp.Model("perishable_inventory")

INV = model.addVars(D, W, vtype=GRB.INTEGER, lb=0, name="INV")
ORD = model.addVars(D, W, vtype=GRB.INTEGER, lb=0, name="ORD")
SPOIL = model.addVars(D, W, vtype=GRB.CONTINUOUS, lb=0, name="SPOIL")

model.setObjective(
    gp.quicksum(hold_cost[d] * INV[d, w] + order_cost[d] * ORD[d, w] + spoil_cost[d] * SPOIL[d, w]
                for d in D for w in W),
    GRB.MINIMIZE
)

for d in D:
    model.addConstr(INV[d, 1] == init_inv[d], name=f"INIT_INV_{d}")

for d in D:
    for w in W:
        model.addConstr(INV[d, w] + SPOIL[d, w] >= demand[d][w-1], name=f"DEMAND_{d}_{w}")

for d in D:
    for w in range(2, W_max + 1):
        model.addConstr(INV[d, w] == INV[d, w-1] + ORD[d, w-1] - demand[d][w-1] + SPOIL[d, w], name=f"INV_TRANSITION_{d}_{w}")

for d in D:
    for w in range(2, W_max + 1):
        model.addConstr(INV[d, w] >= inv_min[d], name=f"INV_LB_{d}_{w}")
        model.addConstr(INV[d, w] <= inv_max[d], name=f"INV_UB_{d}_{w}")

for d in D:
    for w in W:
        model.addConstr(ORD[d, w] <= order_limit[d], name=f"ORDER_LIMIT_{d}_{w}")

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

import gurobipy as gp
from gurobipy import GRB
import json
import os

with open("instance.json") as f:
    inst = json.load(f)

num_ports = inst["num_ports"]
num_hubs = inst["num_hubs"]
num_services = inst["num_services"]
num_containers = inst["num_containers"]
num_hubcap_classes = inst["num_hubcap_classes"]

import pandas as pd

services_df = pd.read_csv("data/services.csv")
service_arcs_df = pd.read_csv("data/service_arcs.csv")
containers_df = pd.read_csv("data/containers.csv")
hubs_df = pd.read_csv("data/hubs.csv")

services = services_df["service_id"].tolist()
containers = containers_df["container_id"].tolist()
hubs = hubs_df["hub_id"].unique().tolist()
hub_classes = hubs_df["hub_class"].unique().tolist()

service_arcs = {}
for _, row in service_arcs_df.iterrows():
    s = row["service_id"]
    a = row["arc_id"]
    if s not in service_arcs:
        service_arcs[s] = []
    service_arcs[s].append(a)

service_cost = {row["service_id"]: row["service_cost"] for _, row in services_df.iterrows()}
service_capacity = {row["service_id"]: row["service_capacity"] for _, row in services_df.iterrows()}

container_origin = {row["container_id"]: row["origin_port"] for _, row in containers_df.iterrows()}
container_destination = {row["container_id"]: row["destination_port"] for _, row in containers_df.iterrows()}
container_deadline = {row["container_id"]: row["deadline"] for _, row in containers_df.iterrows()}
container_volume = {row["container_id"]: row["volume"] for _, row in containers_df.iterrows()}
container_late_penalty_rate = {row["container_id"]: row["late_penalty_rate"] for _, row in containers_df.iterrows()}
container_hub_class = {row["container_id"]: row["hub_class"] for _, row in containers_df.iterrows()}

arc_origin = {}
arc_destination = {}
arc_transit_time = {}
for _, row in service_arcs_df.iterrows():
    s = row["service_id"]
    a = row["arc_id"]
    arc_origin[(s, a)] = row["origin_node"]
    arc_destination[(s, a)] = row["destination_node"]
    arc_transit_time[(s, a)] = row["transit_time"]

hub_capacity = {}
hub_handling_cost = {}
for _, row in hubs_df.iterrows():
    h = row["hub_id"]
    k = row["hub_class"]
    hub_capacity[(h, k)] = row["capacity"]
    hub_handling_cost[(h, k)] = row["handling_cost"]

nodes = set()
for _, row in service_arcs_df.iterrows():
    nodes.add(row["origin_node"])
    nodes.add(row["destination_node"])

model = gp.Model("shipping_network")

z = model.addVars(services, vtype=GRB.BINARY, name="z")
x = model.addVars(containers, services, service_arcs_df["arc_id"].unique(), vtype=GRB.BINARY, name="x")
y = model.addVars(containers, hubs, vtype=GRB.INTEGER, lb=0, name="y")
l = model.addVars(containers, vtype=GRB.INTEGER, lb=0, name="l")
u = model.addVars(containers, vtype=GRB.INTEGER, lb=0, name="u")

model.setObjective(
    gp.quicksum(service_cost[s] * z[s] for s in services)
    + gp.quicksum(container_late_penalty_rate[c] * l[c] for c in containers)
    + gp.quicksum(hub_handling_cost[(h, k)] * container_volume[c] * y[c, h]
                  for c in containers
                  for h in hubs
                  for k in hub_classes if k == container_hub_class[c])
    + gp.quicksum(container_late_penalty_rate[c] * u[c] for c in containers),
    GRB.MINIMIZE
)

for c in containers:
    for s in services:
        for a in service_arcs.get(s, []):
            model.addConstr(x[c, s, a] <= z[s], name=f"service_activation_{c}_{s}_{a}")

for s in services:
    model.addConstr(
        gp.quicksum(container_volume[c] * x[c, s, a] for c in containers for a in service_arcs.get(s, [])) <= service_capacity[s],
        name=f"service_capacity_{s}"
    )

for c in containers:
    for n in nodes:
        outflow = gp.quicksum(x[c, s, a] for s in services for a in service_arcs.get(s, []) if arc_origin[(s, a)] == n)
        inflow = gp.quicksum(x[c, s, a] for s in services for a in service_arcs.get(s, []) if arc_destination[(s, a)] == n)
        rhs = 0
        if n == container_origin[c]:
            rhs = 1
        elif n == container_destination[c]:
            rhs = -1
        model.addConstr(inflow - outflow == rhs, name=f"flow_balance_{c}_{n}")

for c in containers:
    model.addConstr(
        gp.quicksum(x[c, s, a] for s in services for a in service_arcs.get(s, [])) >= 1,
        name=f"route_continuity_{c}"
    )

for c in containers:
    model.addConstr(
        l[c] >= gp.quicksum(arc_transit_time[(s, a)] * x[c, s, a] for s in services for a in service_arcs.get(s, [])) - container_deadline[c],
        name=f"late_time_{c}"
    )

for c in containers:
    for h in hubs:
        model.addConstr(
            y[c, h] == gp.quicksum(x[c, s, a] for s in services for a in service_arcs.get(s, []) if arc_destination[(s, a)] == h),
            name=f"hub_transshipment_{c}_{h}"
        )

for h in hubs:
    for k in hub_classes:
        model.addConstr(
            gp.quicksum(container_volume[c] * y[c, h] for c in containers if container_hub_class[c] == k) <= hub_capacity[(h, k)],
            name=f"hub_capacity_{h}_{k}"
        )

for c in containers:
    model.addConstr(
        u[c] == container_volume[c] - gp.quicksum(container_volume[c] * x[c, s, a] for s in services for a in service_arcs.get(s, [])),
        name=f"unrouted_{c}"
    )

os.makedirs("output", exist_ok=True)
model.write("output/model.lp")

