import gurobipy as gp
from gurobipy import GRB
import json

with open('data.json', 'r') as f:
    data = json.load(f)

PRODUCTS = data['PRODUCTS']
FACTORIES = data['FACTORIES']
WAREHOUSES = data['WAREHOUSES']

profit = data['profit']
fixed_cost = data['fixed_cost']
prod_capacity = data['prod_capacity']
storage_capacity = data['storage_capacity']
demand = data['demand']
ship_limit = data['ship_limit']
min_activation = data['min_activation']
max_activation = data['max_activation']

model = gp.Model('production_network')

ship = {}
for p in PRODUCTS:
    for f in FACTORIES:
        for w in WAREHOUSES:
            ship[p, f, w] = model.addVar(vtype=GRB.INTEGER, lb=0, name=f'ship_{p}_{f}_{w}')

produce = {}
for f in FACTORIES:
    for p in PRODUCTS:
        produce[f, p] = model.addVar(vtype=GRB.INTEGER, lb=0, name=f'produce_{f}_{p}')

store = {}
for w in WAREHOUSES:
    for p in PRODUCTS:
        store[w, p] = model.addVar(vtype=GRB.INTEGER, lb=0, name=f'store_{w}_{p}')

activate = {}
for f in FACTORIES:
    activate[f] = model.addVar(vtype=GRB.BINARY, name=f'activate_{f}')

for f in FACTORIES:
    for p in PRODUCTS:
        model.addConstr(produce[f, p] <= prod_capacity[f][p], name=f'ProdCap_{f}_{p}')

for f in FACTORIES:
    for p in PRODUCTS:
        model.addConstr(gp.quicksum(ship[p, f, w] for w in WAREHOUSES) == produce[f, p], name=f'ProdBalance_{f}_{p}')

for w in WAREHOUSES:
    for p in PRODUCTS:
        model.addConstr(store[w, p] <= storage_capacity[w][p], name=f'StoreCap_{w}_{p}')

for w in WAREHOUSES:
    for p in PRODUCTS:
        model.addConstr(gp.quicksum(ship[p, f, w] for f in FACTORIES) == store[w, p], name=f'StoreBalance_{w}_{p}')

for w in WAREHOUSES:
    for p in PRODUCTS:
        model.addConstr(store[w, p] >= demand[w][p], name=f'DemandSatisfy_{w}_{p}')

for f in FACTORIES:
    for w in WAREHOUSES:
        model.addConstr(gp.quicksum(ship[p, f, w] for p in PRODUCTS) <= ship_limit[f][w], name=f'ShipLimit_{f}_{w}')

for f in FACTORIES:
    for p in PRODUCTS:
        model.addConstr(produce[f, p] <= prod_capacity[f][p] * activate[f], name=f'ActivationProd_{f}_{p}')

model.addConstr(gp.quicksum(activate[f] for f in FACTORIES) >= min_activation, name='MinActivation')
model.addConstr(gp.quicksum(activate[f] for f in FACTORIES) <= max_activation, name='MaxActivation')

obj = gp.quicksum(profit[p][f][w] * ship[p, f, w] for p in PRODUCTS for f in FACTORIES for w in WAREHOUSES) - gp.quicksum(fixed_cost[f] * activate[f] for f in FACTORIES)
model.setObjective(obj, GRB.MAXIMIZE)

model.write('model.lp')

import gurobipy as gp
from gurobipy import GRB
import json
import os

# Read instance.json
with open("instance.json", "r") as f:
    instance = json.load(f)

num_nurses = instance["num_nurses"]
num_units = instance["num_units"]
num_shifts = instance["num_shifts"]
num_slots = instance["num_slots"]
num_days = instance["num_days"]
num_contracts = instance["num_contracts"]

# Sets
NURSES = list(range(1, num_nurses + 1))
UNITS = list(range(1, num_units + 1))
SHIFTS = list(range(1, num_shifts + 1))
SLOTS = list(range(1, num_slots + 1))
DAYS = list(range(1, num_days + 1))
CONTRACTS = list(range(1, num_contracts + 1))

# Read CSV files
import pandas as pd

assign_cost_df = pd.read_csv("data/assign_cost.csv")
penalty_df = pd.read_csv("data/penalty.csv")
demand_df = pd.read_csv("data/demand.csv")
nurse_contract_df = pd.read_csv("data/nurse_contract.csv")
shift_info_df = pd.read_csv("data/shift_info.csv")
overtime_cost_df = pd.read_csv("data/overtime_cost.csv")
skill_compat_df = pd.read_csv("data/skill_compat.csv")
shift_compat_df = pd.read_csv("data/shift_compat.csv")
contract_info_df = pd.read_csv("data/contract_info.csv")
day_off_df = pd.read_csv("data/day_off.csv")

# Build dictionaries
assign_cost = {}
for _, row in assign_cost_df.iterrows():
    n = int(row["nurse_id"])
    u = int(row["unit_id"])
    s = int(row["shift_id"])
    assign_cost[(n, u, s)] = row["cost"]

penalty = {}
for _, row in penalty_df.iterrows():
    u = int(row["unit_id"])
    t = int(row["slot_id"])
    penalty[(u, t)] = row["penalty"]

demand = {}
for _, row in demand_df.iterrows():
    u = int(row["unit_id"])
    t = int(row["slot_id"])
    demand[(u, t)] = row["demand"]

nurse_contract = {}
for _, row in nurse_contract_df.iterrows():
    n = int(row["nurse_id"])
    nurse_contract[n] = {
        "max_shifts": int(row["max_shifts"]),
        "max_hours": row["max_hours"],
        "max_overtime": row["max_overtime"],
        "max_consecutive_shifts": int(row["max_consecutive_shifts"]),
        "contract_type": int(row["contract_type"])
    }

hours_per_shift = {}
for _, row in shift_info_df.iterrows():
    s = int(row["shift_id"])
    hours_per_shift[s] = row["hours_per_shift"]

overtime_cost = {}
for _, row in overtime_cost_df.iterrows():
    n = int(row["nurse_id"])
    s = int(row["shift_id"])
    overtime_cost[(n, s)] = row["overtime_cost"]

skill_compat = {}
for _, row in skill_compat_df.iterrows():
    n = int(row["nurse_id"])
    u = int(row["unit_id"])
    skill_compat[(n, u)] = int(row["compat"])

shift_compat = {}
for _, row in shift_compat_df.iterrows():
    n = int(row["nurse_id"])
    s = int(row["shift_id"])
    shift_compat[(n, s)] = int(row["compat"])

contract_info = {}
for _, row in contract_info_df.iterrows():
    c = int(row["contract_type"])
    contract_info[c] = {
        "min_shifts": int(row["min_shifts"]),
        "max_shifts": int(row["max_shifts"])
    }

day_off_req = {}
for _, row in day_off_df.iterrows():
    n = int(row["nurse_id"])
    d = int(row["day_id"])
    day_off_req[(n, d)] = int(row["day_off"])

# Build slot_shift and slot_unit from the problem description (not provided in files, derive from indices)
# Since no explicit mapping files, we assume slot t corresponds to shift t (mod num_shifts) and unit t (mod num_units)
# But the problem states slot_shift[t,s] and slot_unit[t,u] are parameters.
# Without explicit data, we derive a simple mapping: slot t is associated with shift ((t-1) % num_shifts)+1 and unit ((t-1) % num_units)+1
slot_shift = {}
slot_unit = {}
for t in SLOTS:
    s = ((t - 1) % num_shifts) + 1
    u = ((t - 1) % num_units) + 1
    slot_shift[(t, s)] = 1
    slot_unit[(t, u)] = 1
    # For other combinations, default 0
    for s2 in SHIFTS:
        if s2 != s:
            slot_shift[(t, s2)] = 0
    for u2 in UNITS:
        if u2 != u:
            slot_unit[(t, u2)] = 0

# Build shift_day mapping: shift s occurs on day d if (s-1) % num_days + 1 == d
shift_day = {}
for s in SHIFTS:
    for d in DAYS:
        if ((s - 1) % num_days) + 1 == d:
            shift_day[(s, d)] = 1
        else:
            shift_day[(s, d)] = 0

# Create model
model = gp.Model("NurseAssignment")

# Decision variables
x = {}
for n in NURSES:
    for u in UNITS:
        for s in SHIFTS:
            x[(n, u, s)] = model.addVar(vtype=GRB.BINARY, name=f"x_{n}_{u}_{s}")

y = {}
for n in NURSES:
    for s in SHIFTS:
        y[(n, s)] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"y_{n}_{s}")

z = {}
for u in UNITS:
    for t in SLOTS:
        z[(u, t)] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"z_{u}_{t}")

w = {}
for n in NURSES:
    for d in DAYS:
        w[(n, d)] = model.addVar(vtype=GRB.BINARY, name=f"w_{n}_{d}")

v = {}
for n in NURSES:
    v[n] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"v_{n}")

# Objective: minimize total assignment cost + penalty for uncovered slots
obj = gp.quicksum(assign_cost[(n, u, s)] * x[(n, u, s)] for n in NURSES for u in UNITS for s in SHIFTS if (n, u, s) in assign_cost)
obj += gp.quicksum(penalty[(u, t)] * z[(u, t)] for u in UNITS for t in SLOTS if (u, t) in penalty)
model.setObjective(obj, GRB.MINIMIZE)

# Constraints
# 1. Coverage
for u in UNITS:
    for t in SLOTS:
        lhs = gp.quicksum(x[(n, u, s)] for n in NURSES for s in SHIFTS if slot_shift[(t, s)] == 1) + z[(u, t)]
        model.addConstr(lhs >= demand[(u, t)], name=f"Coverage_{u}_{t}")

# 2. Skill Compatibility
for n in NURSES:
    for u in UNITS:
        for s in SHIFTS:
            if (n, u) in skill_compat:
                model.addConstr(x[(n, u, s)] <= skill_compat[(n, u)], name=f"SkillCompat_{n}_{u}_{s}")

# 3. Shift Compatibility
for n in NURSES:
    for s in SHIFTS:
        lhs = gp.quicksum(x[(n, u, s)] for u in UNITS)
        if (n, s) in shift_compat:
            model.addConstr(lhs <= shift_compat[(n, s)], name=f"ShiftCompat_{n}_{s}")

# 4. Max Shifts
for n in NURSES:
    lhs = gp.quicksum(x[(n, u, s)] for u in UNITS for s in SHIFTS)
    model.addConstr(lhs <= nurse_contract[n]["max_shifts"], name=f"MaxShifts_{n}")

# 5. Max Hours
for n in NURSES:
    lhs = gp.quicksum(hours_per_shift[s] * x[(n, u, s)] for u in UNITS for s in SHIFTS) + v[n]
    model.addConstr(lhs <= nurse_contract[n]["max_hours"], name=f"MaxHours_{n}")

# 6. Overtime Link
for n in NURSES:
    model.addConstr(v[n] == gp.quicksum(y[(n, s)] for s in SHIFTS), name=f"OvertimeLink_{n}")

# 7. Overtime Bound
for n in NURSES:
    for s in SHIFTS:
        lhs = y[(n, s)]
        rhs = nurse_contract[n]["max_overtime"] * gp.quicksum(x[(n, u, s)] for u in UNITS)
        model.addConstr(lhs <= rhs, name=f"OvertimeBound_{n}_{s}")

# 8. Contract Min/Max
for c in CONTRACTS:
    nurses_in_contract = [n for n in NURSES if nurse_contract[n]["contract_type"] == c]
    if nurses_in_contract:
        lhs = gp.quicksum(x[(n, u, s)] for n in nurses_in_contract for u in UNITS for s in SHIFTS)
        model.addConstr(lhs >= contract_info[c]["min_shifts"], name=f"ContractMin_{c}")
        model.addConstr(lhs <= contract_info[c]["max_shifts"], name=f"ContractMax_{c}")

# 9. Day Off
for n in NURSES:
    for d in DAYS:
        if (n, d) in day_off_req and day_off_req[(n, d)] == 1:
            lhs = gp.quicksum(x[(n, u, s)] for u in UNITS for s in SHIFTS if shift_day[(s, d)] == 1)
            model.addConstr(lhs <= 0, name=f"DayOff_{n}_{d}")

# 10. Consecutive Shifts
for n in NURSES:
    max_cons = nurse_contract[n]["max_consecutive_shifts"]
    for d in DAYS:
        if d + max_cons - 1 <= num_days:
            lhs = gp.quicksum(w[(n, k)] for k in range(d, d + max_cons))
            model.addConstr(lhs <= max_cons, name=f"ConsecutiveShifts_{n}_{d}")

# 11. Work Day Link
for n in NURSES:
    for d in DAYS:
        lhs = w[(n, d)]
        rhs = gp.quicksum(x[(n, u, s)] for u in UNITS for s in SHIFTS if shift_day[(s, d)] == 1)
        model.addConstr(lhs >= rhs, name=f"WorkDayLink_{n}_{d}")

# 12. Slot-Shift-Unit Consistency (auxiliary)
for t in SLOTS:
    for s in SHIFTS:
        for u in UNITS:
            model.addConstr(slot_shift[(t, s)] * slot_unit[(t, u)] <= 1, name=f"SlotShiftMap_{t}_{s}_{u}")

# Write LP file
os.makedirs("output", exist_ok=True)
model.write("output/model.lp")

import gurobipy as gp
from gurobipy import GRB
import json

with open('data.json', 'r') as f:
    data = json.load(f)

depots = data['Depots']
grades = data['Grades']
components = data['Components']

profit = data['profit']
comp_ratio = data['comp_ratio']
comp_avail = data['comp_avail']
capacity = data['capacity']
min_output = data['min_output']

model = gp.Model('fuel_blending')

x = {}
y = {}

for d_idx, d in enumerate(depots):
    for g_idx, g in enumerate(grades):
        x[d, g] = model.addVar(vtype=GRB.INTEGER, lb=0, name=f'x_{d}_{g}')
        for c_idx, c in enumerate(components):
            y[d, g, c] = model.addVar(vtype=GRB.INTEGER, lb=0, name=f'y_{d}_{g}_{c}')

model.setObjective(
    gp.quicksum(profit[d_idx][g_idx] * x[d, g]
                for d_idx, d in enumerate(depots)
                for g_idx, g in enumerate(grades)),
    GRB.MAXIMIZE
)

for d_idx, d in enumerate(depots):
    for g_idx, g in enumerate(grades):
        for c_idx, c in enumerate(components):
            model.addConstr(
                y[d, g, c] == comp_ratio[g_idx][c_idx] * x[d, g],
                name=f'blend_{d}_{g}_{c}'
            )

for d_idx, d in enumerate(depots):
    for c_idx, c in enumerate(components):
        model.addConstr(
            gp.quicksum(y[d, g, c] for g_idx, g in enumerate(grades)) <= comp_avail[d_idx][c_idx],
            name=f'avail_{d}_{c}'
        )

for d_idx, d in enumerate(depots):
    model.addConstr(
        gp.quicksum(x[d, g] for g_idx, g in enumerate(grades)) <= capacity[d_idx],
        name=f'cap_{d}'
    )

for d_idx, d in enumerate(depots):
    for g_idx, g in enumerate(grades):
        model.addConstr(
            x[d, g] >= min_output[d_idx][g_idx],
            name=f'minout_{d}_{g}'
        )

model.write('model.lp')

