import gurobipy as gp
from gurobipy import GRB
import json
import pandas as pd

# Read instance.json
with open('instance.json') as f:
    instance = json.load(f)
M = instance['M']

# Read CSV files
trailers = pd.read_csv('data/trailers.csv')
doors = pd.read_csv('data/doors.csv')
handling_costs = pd.read_csv('data/handling_costs.csv')
door_capacity = pd.read_csv('data/door_capacity.csv')
zone_demand = pd.read_csv('data/zone_demand.csv')
shifts = pd.read_csv('data/shifts.csv')
shift_door_assign = pd.read_csv('data/shift_door_assign.csv')

# Sets
trailers_list = trailers['trailer_id'].tolist()
doors_list = doors['door_id'].tolist()
shifts_list = shifts['shift_id'].tolist()
days = sorted(door_capacity['day'].unique())
zones = sorted(zone_demand['zone'].unique())
types = doors['compatibility_types'].unique()

# Parameters
trailer_type = dict(zip(trailers['trailer_id'], trailers['type']))
trailer_arrival = dict(zip(trailers['trailer_id'], trailers['arrival_day']))
trailer_deadline = dict(zip(trailers['trailer_id'], trailers['deadline_day']))
trailer_zone = dict(zip(trailers['trailer_id'], trailers['zone']))
trailer_volume = dict(zip(trailers['trailer_id'], trailers['volume']))
delay_cost = dict(zip(trailers['trailer_id'], trailers['delay_cost']))
reassign_cost = dict(zip(trailers['trailer_id'], trailers['reassign_cost']))

handling_cost = {}
for _, row in handling_costs.iterrows():
    handling_cost[(row['trailer_id'], row['door_id'])] = row['cost']

door_pallet_cap = {}
door_max_trailers = {}
door_max_shifts = {}
for _, row in door_capacity.iterrows():
    door_pallet_cap[(row['door_id'], row['day'])] = row['pallet_capacity']
    door_max_trailers[(row['door_id'], row['day'])] = row['max_trailers']
    door_max_shifts[(row['door_id'], row['day'])] = row['max_shifts']

zone_demand_dict = {}
zone_penalty = {}
for _, row in zone_demand.iterrows():
    zone_demand_dict[(row['zone'], row['day'])] = row['demand']
    zone_penalty[row['zone']] = row['penalty']

wage_cost = dict(zip(shifts['shift_id'], shifts['wage_cost']))

shift_door_cost = {}
for _, row in shift_door_assign.iterrows():
    shift_door_cost[(row['shift_id'], row['door_id'])] = row['cost']

# Compatibility matrix
door_type_compat = {}
for _, row in doors.iterrows():
    compat_types = row['compatibility_types'].split(',')
    for t in types:
        door_type_compat[(row['door_id'], t)] = 1 if t in compat_types else 0

# Create model
model = gp.Model('cross_dock_scheduling')

# Decision variables
x = model.addVars(trailers_list, doors_list, shifts_list, vtype=GRB.INTEGER, lb=0, ub=1, name='x')
y = model.addVars(trailers_list, days, vtype=GRB.INTEGER, lb=0, name='y')
z = model.addVars(trailers_list, days, vtype=GRB.INTEGER, lb=0, ub=1, name='z')
u = model.addVars(zones, days, vtype=GRB.CONTINUOUS, lb=0, name='u')
v = model.addVars(shifts_list, doors_list, days, vtype=GRB.INTEGER, lb=0, ub=1, name='v')

# Objective: minimize total cost
obj = gp.QuadExpr()
# Handling cost
for t in trailers_list:
    for d in doors_list:
        for s in shifts_list:
            if (t, d) in handling_cost:
                obj += handling_cost[(t, d)] * x[t, d, s]
# Delay cost
for t in trailers_list:
    for n in days:
        obj += delay_cost[t] * y[t, n]
# Reassignment cost
for t in trailers_list:
    for n in days:
        obj += reassign_cost[t] * z[t, n]
# Zone penalty
for z_ in zones:
    for n in days:
        obj += zone_penalty[z_] * u[z_, n]
# Labor cost (wage + shift-door assignment)
for s in shifts_list:
    for d in doors_list:
        for n in days:
            obj += wage_cost[s] * v[s, d, n]
            if (s, d) in shift_door_cost:
                obj += shift_door_cost[(s, d)] * v[s, d, n]

model.setObjective(obj, GRB.MINIMIZE)

# Constraints
# 1. Each trailer assigned to exactly one door-shift or delayed
for t in trailers_list:
    model.addConstr(
        gp.quicksum(x[t, d, s] for d in doors_list for s in shifts_list) +
        gp.quicksum(y[t, n] for n in days) == 1,
        name=f'trailer_assignment_{t}'
    )

# 2. Delay indicator per day
for t in trailers_list:
    for n in days:
        model.addConstr(y[t, n] <= 1, name=f'delay_def_{t}_{n}')

# 3. Delay only within allowed window
for t in trailers_list:
    for n in days:
        if n < trailer_arrival[t] or n > trailer_deadline[t]:
            model.addConstr(y[t, n] == 0, name=f'delay_window_{t}_{n}')

# 4. Type compatibility
for t in trailers_list:
    for d in doors_list:
        for s in shifts_list:
            model.addConstr(
                x[t, d, s] <= door_type_compat[(d, trailer_type[t])],
                name=f'type_compat_{t}_{d}_{s}'
            )

# 5. Pallet volume capacity per door per day
for d in doors_list:
    for n in days:
        model.addConstr(
            gp.quicksum(trailer_volume[t] * x[t, d, s] for t in trailers_list for s in shifts_list) <= door_pallet_cap[(d, n)],
            name=f'door_pallet_cap_{d}_{n}'
        )

# 6. Max trailers per door per day
for d in doors_list:
    for n in days:
        model.addConstr(
            gp.quicksum(x[t, d, s] for t in trailers_list for s in shifts_list) <= door_max_trailers[(d, n)],
            name=f'door_trailer_cap_{d}_{n}'
        )

# 7. Zone service level
for z_ in zones:
    for n in days:
        model.addConstr(
            gp.quicksum(trailer_volume[t] * x[t, d, s] for t in trailers_list if trailer_zone[t] == z_ for d in doors_list for s in shifts_list) + u[z_, n] >= zone_demand_dict[(z_, n)],
            name=f'zone_service_{z_}_{n}'
        )

# 8. Shift assigned to door only if at least one trailer assigned
for s in shifts_list:
    for d in doors_list:
        for n in days:
            model.addConstr(
                v[s, d, n] <= gp.quicksum(x[t, d, s] for t in trailers_list),
                name=f'shift_assign_{s}_{d}_{n}'
            )

# 9. Trailer assignment implies shift-door assignment (big-M)
for s in shifts_list:
    for d in doors_list:
        for n in days:
            model.addConstr(
                gp.quicksum(x[t, d, s] for t in trailers_list) <= M * v[s, d, n],
                name=f'shift_door_link_{s}_{d}_{n}'
            )

# 10. Limit shifts per door per day
for d in doors_list:
    for n in days:
        model.addConstr(
            gp.quicksum(v[s, d, n] for s in shifts_list) <= door_max_shifts[(d, n)],
            name=f'max_shifts_{d}_{n}'
        )

# 11. Reassignment indicator
for t in trailers_list:
    for n in days:
        if n > min(days):
            prev_day = n - 1
            model.addConstr(
                z[t, n] >= y[t, n] - y[t, prev_day],
                name=f'reassign_link_{t}_{n}'
            )
        else:
            model.addConstr(z[t, n] >= y[t, n], name=f'reassign_link_{t}_{n}')

# Solve
model.optimize()

# Print results
if model.Status == GRB.OPTIMAL:
    print(f'optimal_value = {model.ObjVal}')
else:
    print(f'Optimization status: {model.Status}')
    if model.Status == GRB.INFEASIBLE:
        print('optimal_value = INFEASIBLE')
    elif model.Status == GRB.UNBOUNDED:
        print('optimal_value = UNBOUNDED')
    else:
        print('optimal_value = ERROR')

