import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

C = data["C"]
H = data["H"]
B = data["B"]

supply = data["supply"]
demand = data["demand"]
shortage_cost = data["shortage_cost"]
perishability_rate = data["perishability_rate"]
max_transport = data["max_transport"]
initial_inventory = data["initial_inventory"]
storage_capacity = data["storage_capacity"]

model = gp.Model("blood_bank_optimization")

allocation = {}
shortage = {}
inventory = {}

for c in C:
    for b in B:
        for h in H:
            allocation[c, b, h] = model.addVar(lb=0, name=f"allocation_{c}_{b}_{h}")
            shortage[c, b, h] = model.addVar(lb=0, name=f"shortage_{c}_{b}_{h}")
for c in C:
    for b in B:
        inventory[c, b] = model.addVar(lb=0, name=f"inventory_{c}_{b}")

model.setObjective(
    gp.quicksum(shortage_cost[c][b][h] * shortage[c, b, h] for c in C for b in B for h in H),
    GRB.MINIMIZE
)

for c in C:
    for b in B:
        model.addConstr(
            gp.quicksum(allocation[c, b, h] for h in H) + inventory[c, b] <= supply[c][b] + initial_inventory[c][b],
            name=f"supply_limit_{c}_{b}"
        )

for h in H:
    for b in B:
        model.addConstr(
            gp.quicksum(allocation[c, b, h] + shortage[c, b, h] for c in C) >= demand[h][b],
            name=f"demand_meet_{h}_{b}"
        )

for c in C:
    for b in B:
        model.addConstr(
            gp.quicksum(allocation[c, b, h] for h in H) <= (1 - perishability_rate[b]) * (supply[c][b] + initial_inventory[c][b]),
            name=f"perishability_{c}_{b}"
        )

for c in C:
    for h in H:
        model.addConstr(
            gp.quicksum(allocation[c, b, h] for b in B) <= max_transport[c][h],
            name=f"transport_capacity_{c}_{h}"
        )

for c in C:
    model.addConstr(
        gp.quicksum(inventory[c, b] for b in B) <= storage_capacity[c],
        name=f"storage_capacity_{c}"
    )

for c in C:
    for b in B:
        model.addConstr(
            inventory[c, b] == initial_inventory[c][b] + supply[c][b] - gp.quicksum(allocation[c, b, h] for h in H),
            name=f"inventory_balance_{c}_{b}"
        )

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

looms = data["Looms"]
fabrics = data["Fabrics"]
orders = data["Orders"]

prod_cost = data["prod_cost"]
setup_cost = data["setup_cost"]
capacity_hours = data["capacity_hours"]
prod_rate = data["prod_rate"]
order_demand = data["order_demand"]
order_deadline = data["order_deadline"]
order_fabric = data["order_fabric"]
bigM = data["bigM"]

model = gp.Model("textile_production")

prod = {}
setup = {}
for i, l in enumerate(looms):
    for j, f in enumerate(fabrics):
        prod[l, f] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"prod_{l}_{f}")
        setup[l, f] = model.addVar(lb=0, ub=1, vtype=GRB.CONTINUOUS, name=f"setup_{l}_{f}")

model.setObjective(
    gp.quicksum(prod_cost[i][j] * prod[l, f] + setup_cost[i][j] * setup[l, f]
                for i, l in enumerate(looms) for j, f in enumerate(fabrics)),
    GRB.MINIMIZE
)

for i, l in enumerate(looms):
    model.addConstr(
        gp.quicksum(prod[l, f] / prod_rate[i][j] for j, f in enumerate(fabrics)) <= capacity_hours[i],
        name=f"capacity_{l}"
    )

for o_idx, o in enumerate(orders):
    f_idx = order_fabric[o_idx]
    f = fabrics[f_idx]
    model.addConstr(
        gp.quicksum(prod[l, f] for l in looms) >= order_demand[o_idx][f_idx],
        name=f"demand_{o}"
    )

for i, l in enumerate(looms):
    for j, f in enumerate(fabrics):
        model.addConstr(
            prod[l, f] <= setup[l, f] * bigM,
            name=f"setup_activation_{l}_{f}"
        )

for i, l in enumerate(looms):
    for o_idx, o in enumerate(orders):
        model.addConstr(
            gp.quicksum(prod[l, f] / prod_rate[i][j] for j, f in enumerate(fabrics)) <= order_deadline[o_idx],
            name=f"deadline_{l}_{o}"
        )

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

problem:
A district heating network consists of heat production plants, substations, and customer zones. Heat is produced at plants, transmitted through pipelines to substations, and then distributed to customer zones. The objective is to maximize total profit from heat delivery. The following data are provided in data.json:

- Sets: P (plants), S (substations), Z (zones).
- Parameters:
  - prod_cap[p]: maximum heat output at plant p (MW).
  - pipeline_cap[p][s]: maximum heat flow from plant p to substation s (MW).
  - substation_cap[s]: maximum heat throughput at substation s (MW).
  - zone_demand[z]: heat demand at customer zone z (MW).
  - profit[p][s]: profit per MW from plant p to substation s.
  - profit_z[s][z]: profit per MW from substation s to zone z.
