import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

P = data["P"]
S = data["S"]
Z = data["Z"]

prod_cap = data["prod_cap"]
pipeline_cap = data["pipeline_cap"]
substation_cap = data["substation_cap"]
zone_demand = data["zone_demand"]
profit = data["profit"]
profit_z = data["profit_z"]
temp_loss = data["temp_loss"]
min_temp = data["min_temp"]
plant_temp = data["plant_temp"]

model = gp.Model("district_heating_network")

f = {}
for p in P:
    for s in S:
        f[p, s] = model.addVar(lb=0, name=f"f_{p}_{s}")

g = {}
for s in S:
    for z in Z:
        g[s, z] = model.addVar(lb=0, name=f"g_{s}_{z}")

model.setObjective(
    gp.quicksum(profit[p][s] * f[p, s] for p in P for s in S) +
    gp.quicksum(profit_z[s][z] * g[s, z] for s in S for z in Z),
    GRB.MAXIMIZE
)

for p in P:
    model.addConstr(
        gp.quicksum(f[p, s] for s in S) <= prod_cap[p],
        name=f"ProductionLimit_{p}"
    )

for p in P:
    for s in S:
        model.addConstr(
            f[p, s] <= pipeline_cap[p][s],
            name=f"PipelineFlowLimit_{p}_{s}"
        )

for s in S:
    model.addConstr(
        gp.quicksum(f[p, s] for p in P) - gp.quicksum(g[s, z] for z in Z) == 0,
        name=f"SubstationBalance_{s}"
    )

for s in S:
    model.addConstr(
        gp.quicksum(f[p, s] for p in P) <= substation_cap[s],
        name=f"SubstationThroughput_{s}"
    )

for z in Z:
    model.addConstr(
        gp.quicksum(g[s, z] for s in S) >= zone_demand[z],
        name=f"DemandSatisfaction_{z}"
    )

for p in P:
    for s in S:
        for z in Z:
            model.addConstr(
                plant_temp[p] - temp_loss[p][s] >= min_temp[z],
                name=f"TemperatureDrop_{p}_{s}_{z}"
            )

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

I = data["I"]
G = data["G"]
A = data["A"]
cost = data["cost"]
avail = data["avail"]
demand = data["demand"]
max_prod = data["max_prod"]
quality_contrib = data["quality_contrib"]
lower_ratio = data["lower_ratio"]
upper_ratio = data["upper_ratio"]
min_output = data["min_output"]

model = gp.Model("paint_blending")

x = {}
for i in I:
    for g in G:
        x[i, g] = model.addVar(lb=0, name=f"x_{i}_{g}")

y = {}
for g in G:
    y[g] = model.addVar(lb=0, name=f"y_{g}")

model.setObjective(gp.quicksum(cost[i] * x[i, g] for i in I for g in G), GRB.MINIMIZE)

for i in I:
    model.addConstr(gp.quicksum(x[i, g] for g in G) <= avail[i], name=f"ingredient_avail_{i}")

for g in G:
    model.addConstr(gp.quicksum(x[i, g] for i in I) == y[g], name=f"blend_def_{g}")

for g in G:
    model.addConstr(y[g] >= demand[g], name=f"demand_satisfy_{g}")

for g in G:
    model.addConstr(y[g] <= max_prod[g], name=f"max_prod_limit_{g}")

model.addConstr(gp.quicksum(y[g] for g in G) >= min_output, name="min_total_output")

for g in G:
    for a in A:
        key_lower = f"{g}_{a}"
        key_upper = f"{g}_{a}"
        model.addConstr(gp.quicksum(quality_contrib[f"{i}_{a}"] * x[i, g] for i in I) >= lower_ratio[key_lower] * y[g], name=f"lower_quality_ratio_{g}_{a}")
        model.addConstr(gp.quicksum(quality_contrib[f"{i}_{a}"] * x[i, g] for i in I) <= upper_ratio[key_upper] * y[g], name=f"upper_quality_ratio_{g}_{a}")

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

import gurobipy as gp
from gurobipy import GRB
import json
import os

# Read instance.json
with open('instance.json') as f:
    instance = json.load(f)
num_days = instance['num_days']
big_M = instance['big_M']

# Read containers.csv
import csv
containers = {}
with open('data/containers.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        cid = row['container_id']
        containers[cid] = {
            'arrival_day': int(row['arrival_day']),
            'weight': float(row['weight']),
            'dest': row['dest'],
            'container_type': row['container_type'],
            'tardy_penalty': float(row['tardy_penalty']),
            'due_day': int(row['due_day']),
            'processing_time': float(row['processing_time'])
        }

# Read slots.csv
slots = {}
with open('data/slots.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        sid = row['slot_id']
        slots[sid] = {
            'slot_cost': float(row['slot_cost']),
            'slot_capacity': float(row['slot_capacity']),
            'slot_type': row['slot_type'],
            'slot_hours_per_day': float(row['slot_hours_per_day'])
        }

# Read compatibility.csv
compatible = set()
with open('data/compatibility.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        compatible.add((row['container_id'], row['slot_id']))

# Build model
model = gp.Model('container_yard')

# Decision variables
y = {}
for c in containers:
    for s in slots:
        y[c, s] = model.addVar(vtype=GRB.BINARY, name=f'y_{c}_{s}')

start = {}
for c in containers:
    start[c] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f'start_{c}')

late = {}
for c in containers:
    late[c] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f'late_{c}')

# Objective: minimize slot assignment costs + tardiness penalties
obj = gp.QuadExpr()
for c in containers:
    for s in slots:
        obj += slots[s]['slot_cost'] * y[c, s]
for c in containers:
    obj += containers[c]['tardy_penalty'] * late[c]
model.setObjective(obj, GRB.MINIMIZE)

# Constraint: each container assigned to exactly one slot
for c in containers:
    model.addConstr(gp.quicksum(y[c, s] for s in slots) == 1, name=f'assign_once_{c}')

# Constraint: assignment only allowed for compatible pairs
for c in containers:
    for s in slots:
        if (c, s) not in compatible:
            model.addConstr(y[c, s] == 0, name=f'compatibility_{c}_{s}')

# Constraint: total weight assigned to slot s cannot exceed its capacity
for s in slots:
    model.addConstr(
        gp.quicksum(containers[c]['weight'] * y[c, s] for c in containers) <= slots[s]['slot_capacity'],
        name=f'slot_capacity_{s}'
    )

# Constraint: total processing hours at slot s cannot exceed available hours over horizon
for s in slots:
    model.addConstr(
        gp.quicksum(containers[c]['processing_time'] * y[c, s] for c in containers) <= slots[s]['slot_hours_per_day'] * num_days,
        name=f'slot_hours_{s}'
    )

# Constraint: processing cannot start before container arrives
for c in containers:
    model.addConstr(start[c] >= (containers[c]['arrival_day'] - 1) * 24, name=f'start_after_arrival_{c}')

# Constraint: tardiness definition
for c in containers:
    model.addConstr(late[c] >= (start[c] / 24 + 1) - containers[c]['due_day'], name=f'tardiness_definition_{c}')

# Constraint: start time is zero if container not assigned to slot (linking)
for c in containers:
    for s in slots:
        model.addConstr(start[c] <= big_M * y[c, s], name=f'start_linking_{c}_{s}')

# Write LP file
lp_path = 'output/model.lp'
os.makedirs(os.path.dirname(lp_path), exist_ok=True)
model.write(lp_path)

