import gurobipy as gp
from gurobipy import GRB
import json

with open('data.json', 'r') as f:
    data = json.load(f)

centers = data['centers']
accounts = data['accounts']
service_cost = data['service_cost']
region_capacity = data['region_capacity']
min_centers_per_region = data['min_centers_per_region']

center_ids = [c['center_id'] for c in centers]
account_ids = [a['account_id'] for a in accounts]
region_ids = list(set(c['region_id'] for c in centers))

center_region = {c['center_id']: c['region_id'] for c in centers}
account_region = {a['account_id']: a['region_id'] for a in accounts}
fixed_cost = {c['center_id']: c['fixed_cost'] for c in centers}
capacity = {c['center_id']: c['capacity'] for c in centers}
max_assign = {c['center_id']: c['max_assign'] for c in centers}
region_cap = {r['region_id']: r['capacity'] for r in region_capacity}
min_centers = {r['region_id']: r['min_centers'] for r in min_centers_per_region}

cost_dict = {}
for sc in service_cost:
    cost_dict[(sc['account_id'], sc['center_id'])] = sc['cost']

model = gp.Model('service_center_selection')

activate = model.addVars(center_ids, vtype=GRB.BINARY, name='activate')
assign = model.addVars(account_ids, center_ids, lb=0, ub=1, vtype=GRB.CONTINUOUS, name='assign')

model.setObjective(
    gp.quicksum(fixed_cost[c] * activate[c] for c in center_ids) +
    gp.quicksum(cost_dict[(a, c)] * assign[a, c] for a in account_ids for c in center_ids if (a, c) in cost_dict),
    GRB.MINIMIZE
)

for a in account_ids:
    model.addConstr(gp.quicksum(assign[a, c] for c in center_ids) == 1, name=f'assignment_exact_{a}')

for c in center_ids:
    model.addConstr(gp.quicksum(assign[a, c] for a in account_ids) <= capacity[c], name=f'center_capacity_{c}')

for a in account_ids:
    for c in center_ids:
        model.addConstr(assign[a, c] <= activate[c], name=f'activation_linking_{a}_{c}')

for r in region_ids:
    model.addConstr(
        gp.quicksum(assign[a, c] for a in account_ids if account_region[a] == r for c in center_ids if center_region[c] == r) <= region_cap[r],
        name=f'region_capacity_{r}'
    )

for r in region_ids:
    model.addConstr(
        gp.quicksum(activate[c] for c in center_ids if center_region[c] == r) >= min_centers[r],
        name=f'min_centers_region_{r}'
    )

for c in center_ids:
    model.addConstr(gp.quicksum(assign[a, c] for a in account_ids) <= max_assign[c], name=f'max_assign_per_center_{c}')

model.write('model.lp')

import gurobipy as gp
from gurobipy import GRB
import json
import pandas as pd

# Read instance.json
with open('instance.json') as f:
    instance_data = json.load(f)
min_service_level = instance_data['min_service_level']
bigM = instance_data['bigM']

# Read CSV files
plants_df = pd.read_csv('data/plants.csv')
warehouses_df = pd.read_csv('data/warehouses.csv')
customers_df = pd.read_csv('data/customers.csv')
families_df = pd.read_csv('data/families.csv')
periods_df = pd.read_csv('data/periods.csv')
shift_types_df = pd.read_csv('data/shift_types.csv')
production_df = pd.read_csv('data/production.csv')
inventory_df = pd.read_csv('data/inventory.csv')
transportation_df = pd.read_csv('data/transportation.csv')
demand_df = pd.read_csv('data/demand.csv')
distribution_df = pd.read_csv('data/distribution.csv')
labor_df = pd.read_csv('data/labor.csv')

# Sets
PLANTS = list(plants_df['plant_id'].unique())
WAREHOUSES = list(warehouses_df['warehouse_id'].unique())
CUSTOMERS = list(customers_df['customer_id'].unique())
FAMILIES = list(families_df['family_id'].unique())
PERIODS = list(periods_df['period_id'].unique())
SHIFT_TYPES = list(shift_types_df['shift_type_id'].unique())

# Parameters
labor_hours_per_unit = dict(zip(families_df['family_id'], families_df['labor_hours_per_unit']))

prod_cap = {}
prod_cost = {}
for _, row in production_df.iterrows():
    key = (row['plant_id'], row['family_id'], row['period_id'])
    prod_cap[key] = row['prod_cap']
    prod_cost[key] = row['prod_cost']

inv_cap = {}
inv_cost = {}
init_inv = {}
for _, row in inventory_df.iterrows():
    key = (row['warehouse_id'], row['family_id'], row['period_id'])
    inv_cap[key] = row['inv_cap']
    inv_cost[key] = row['inv_cost']
    init_inv_key = (row['warehouse_id'], row['family_id'])
    if row['period_id'] == PERIODS[0]:
        init_inv[init_inv_key] = row['init_inv']

trans_cost = {}
trans_cap = {}
for _, row in transportation_df.iterrows():
    key = (row['plant_id'], row['warehouse_id'], row['family_id'], row['period_id'])
    trans_cost[key] = row['trans_cost']
    trans_cap[key] = row['trans_cap']

demand = {}
short_cost = {}
max_short = {}
for _, row in demand_df.iterrows():
    key = (row['customer_id'], row['family_id'], row['period_id'])
    demand[key] = row['demand']
    short_cost[key] = row['short_cost']
    max_short[key] = row['max_short']

dist_matrix = {}
for _, row in distribution_df.iterrows():
    key = (row['warehouse_id'], row['customer_id'])
    dist_matrix[key] = row['dist_matrix']

labor_available = {}
for _, row in labor_df.iterrows():
    key = (row['plant_id'], row['shift_type_id'], row['period_id'])
    labor_available[key] = row['labor_available']

# Model
model = gp.Model('multi_plant_production_distribution')

# Decision variables
prod = model.addVars(PLANTS, FAMILIES, PERIODS, vtype=GRB.INTEGER, lb=0, name='prod')
inv = model.addVars(WAREHOUSES, FAMILIES, PERIODS, vtype=GRB.CONTINUOUS, lb=0, name='inv')
ship = model.addVars(PLANTS, WAREHOUSES, FAMILIES, PERIODS, vtype=GRB.CONTINUOUS, lb=0, name='ship')
short = model.addVars(CUSTOMERS, FAMILIES, PERIODS, vtype=GRB.CONTINUOUS, lb=0, name='short')
labor_used = model.addVars(PLANTS, SHIFT_TYPES, PERIODS, vtype=GRB.CONTINUOUS, lb=0, name='labor_used')

# Objective
obj = gp.QuadExpr()
for p in PLANTS:
    for f in FAMILIES:
        for t in PERIODS:
            if (p, f, t) in prod_cost:
                obj += prod_cost[(p, f, t)] * prod[p, f, t]
for w in WAREHOUSES:
    for f in FAMILIES:
        for t in PERIODS:
            if (w, f, t) in inv_cost:
                obj += inv_cost[(w, f, t)] * inv[w, f, t]
for p in PLANTS:
    for w in WAREHOUSES:
        for f in FAMILIES:
            for t in PERIODS:
                if (p, w, f, t) in trans_cost:
                    obj += trans_cost[(p, w, f, t)] * ship[p, w, f, t]
for c in CUSTOMERS:
    for f in FAMILIES:
        for t in PERIODS:
            if (c, f, t) in short_cost:
                obj += short_cost[(c, f, t)] * short[c, f, t]
model.setObjective(obj, GRB.MINIMIZE)

# Constraints
# Production capacity
for p in PLANTS:
    for f in FAMILIES:
        for t in PERIODS:
            if (p, f, t) in prod_cap:
                model.addConstr(prod[p, f, t] <= prod_cap[(p, f, t)], name=f'prod_capacity_{p}_{f}_{t}')

# Inventory balance
for w in WAREHOUSES:
    for f in FAMILIES:
        for t in PERIODS:
            inflow = gp.quicksum(ship[p, w, f, t] for p in PLANTS)
            outflow = gp.quicksum(dist_matrix.get((w, c), 0) * (demand.get((c, f, t), 0) - short[c, f, t]) for c in CUSTOMERS)
            if t == PERIODS[0]:
                init = init_inv.get((w, f), 0)
                model.addConstr(inv[w, f, t] == init + inflow - outflow, name=f'inv_balance_{w}_{f}_{t}')
            else:
                prev_t = PERIODS[PERIODS.index(t) - 1]
                model.addConstr(inv[w, f, t] == inv[w, f, prev_t] + inflow - outflow, name=f'inv_balance_{w}_{f}_{t}')

# Inventory capacity
for w in WAREHOUSES:
    for f in FAMILIES:
        for t in PERIODS:
            if (w, f, t) in inv_cap:
                model.addConstr(inv[w, f, t] <= inv_cap[(w, f, t)], name=f'inv_capacity_{w}_{f}_{t}')

# Transportation capacity
for p in PLANTS:
    for w in WAREHOUSES:
        for f in FAMILIES:
            for t in PERIODS:
                if (p, w, f, t) in trans_cap:
                    model.addConstr(ship[p, w, f, t] <= trans_cap[(p, w, f, t)], name=f'trans_capacity_{p}_{w}_{f}_{t}')

# Demand satisfaction
for c in CUSTOMERS:
    for f in FAMILIES:
        for t in PERIODS:
            key = (c, f)
            if key in min_service_level:
                lhs = gp.quicksum(dist_matrix.get((w, c), 0) * (demand.get((c, f, t), 0) - short[c, f, t]) for w in WAREHOUSES)
                rhs = min_service_level[key] * demand.get((c, f, t), 0)
                model.addConstr(lhs >= rhs, name=f'demand_satisfaction_{c}_{f}_{t}')

# Shortage upper bound
for c in CUSTOMERS:
    for f in FAMILIES:
        for t in PERIODS:
            if (c, f, t) in max_short:
                model.addConstr(short[c, f, t] <= max_short[(c, f, t)], name=f'short_upper_{c}_{f}_{t}')

# Labor balance
for p in PLANTS:
    for t in PERIODS:
        lhs = gp.quicksum(labor_hours_per_unit[f] * prod[p, f, t] for f in FAMILIES)
        rhs = gp.quicksum(labor_used[p, s, t] for s in SHIFT_TYPES)
        model.addConstr(lhs <= rhs, name=f'labor_balance_{p}_{t}')

# Labor availability
for p in PLANTS:
    for s in SHIFT_TYPES:
        for t in PERIODS:
            if (p, s, t) in labor_available:
                model.addConstr(labor_used[p, s, t] <= labor_available[(p, s, t)], name=f'labor_available_{p}_{s}_{t}')

# Solve
model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
else:
    print(f"Optimization status: {model.Status}")
    if model.Status == GRB.INFEASIBLE:
        print("optimal_value = INFEASIBLE")
    elif model.Status == GRB.UNBOUNDED:
        print("optimal_value = UNBOUNDED")
    else:
        print("optimal_value = ERROR")

