import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

PLANTS = data["PLANTS"]
CUSTOMERS = data["CUSTOMERS"]
PERIODS = data["PERIODS"]

capacity = data["capacity"]
fuel_consumption_rate = data["fuel_consumption_rate"]
fuel_available = data["fuel_available"]
fuel_cost = data["fuel_cost"]
emission_rate = data["emission_rate"]
emission_limit = data["emission_limit"]
demand = data["demand"]
revenue = data["revenue"]
startup_cost = data["startup_cost"]
ramp_up_limit = data["ramp_up_limit"]
ramp_down_limit = data["ramp_down_limit"]
min_generation = data["min_generation"]

model = gp.Model("energy_utility")

x = {}
for i in PLANTS:
    for j in CUSTOMERS:
        for t in PERIODS:
            x[i, j, t] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"x_{i}_{j}_{t}")

y = {}
for i in PLANTS:
    for t in PERIODS:
        y[i, t] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"y_{i}_{t}")

z = {}
for i in PLANTS:
    for t in PERIODS:
        z[i, t] = model.addVar(lb=0, ub=1, vtype=GRB.CONTINUOUS, name=f"z_{i}_{t}")

model.setObjective(
    gp.quicksum(revenue[i][j][t] * x[i, j, t] for i in PLANTS for j in CUSTOMERS for t in PERIODS)
    - gp.quicksum(startup_cost[i][t] * z[i, t] for i in PLANTS for t in PERIODS)
    - gp.quicksum(fuel_cost[i] * y[i, t] for i in PLANTS for t in PERIODS),
    GRB.MAXIMIZE
)

for i in PLANTS:
    for t in PERIODS:
        model.addConstr(
            gp.quicksum(x[i, j, t] for j in CUSTOMERS) == y[i, t],
            name=f"generation_balance_{i}_{t}"
        )

for i in PLANTS:
    for t in PERIODS:
        model.addConstr(y[i, t] <= capacity[i][t], name=f"capacity_limit_{i}_{t}")

for t in PERIODS:
    model.addConstr(
        gp.quicksum(fuel_consumption_rate[i] * y[i, t] for i in PLANTS) <= fuel_available[t],
        name=f"fuel_limit_{t}"
    )

for t in PERIODS:
    model.addConstr(
        gp.quicksum(emission_rate[i] * y[i, t] for i in PLANTS) <= emission_limit[t],
        name=f"emission_limit_{t}"
    )

for j in CUSTOMERS:
    for t in PERIODS:
        model.addConstr(
            gp.quicksum(x[i, j, t] for i in PLANTS) >= demand[j][t],
            name=f"demand_coverage_{j}_{t}"
        )

for i in PLANTS:
    for t_idx in range(1, len(PERIODS)):
        t_prev = PERIODS[t_idx - 1]
        t_curr = PERIODS[t_idx]
        model.addConstr(
            y[i, t_curr] - y[i, t_prev] <= ramp_up_limit[i],
            name=f"ramp_up_{i}_{t_curr}"
        )
        model.addConstr(
            y[i, t_prev] - y[i, t_curr] <= ramp_down_limit[i],
            name=f"ramp_down_{i}_{t_curr}"
        )

for i in PLANTS:
    for t in PERIODS:
        model.addConstr(
            y[i, t] >= min_generation[i][t] * z[i, t],
            name=f"min_generation_online_{i}_{t}"
        )

model.write("model.lp")

