import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

films = [film["film_id"] for film in data["films"]]
slots = [slot["slot_id"] for slot in data["slots"]]
genres = [genre["genre_id"] for genre in data["genres"]]

film_length = {film["film_id"]: film["film_length"] for film in data["films"]}
slot_duration = {slot["slot_id"]: slot["slot_duration"] for slot in data["slots"]}
max_films_per_slot = {slot["slot_id"]: slot["max_films_per_slot"] for slot in data["slots"]}
min_director_available = {slot["slot_id"]: slot["min_director_available"] for slot in data["slots"]}
min_genre_films = {genre["genre_id"]: genre["min_genre_films"] for genre in data["genres"]}

appeal = {}
for entry in data["appeal"]:
    appeal[(entry["film_id"], entry["slot_id"])] = entry["appeal_score"]

genre_ind = {}
for entry in data["genre"]:
    genre_ind[(entry["film_id"], entry["genre_id"])] = entry["indicator"]

director_available = {}
for entry in data["director_available"]:
    val = entry["indicator"]
    if val is None:
        val = 0
    director_available[(entry["film_id"], entry["slot_id"])] = val

model = gp.Model("film_festival")

x = model.addVars(films, slots, vtype=GRB.BINARY, name="x")
y = model.addVars(films, vtype=GRB.BINARY, name="y")

model.setObjective(gp.quicksum(appeal[(f, s)] * x[f, s] for f in films for s in slots), GRB.MAXIMIZE)

for f in films:
    for s in slots:
        model.addConstr(x[f, s] <= y[f], name=f"film_selection_link_{f}_{s}")

for s in slots:
    model.addConstr(gp.quicksum(x[f, s] for f in films) <= max_films_per_slot[s], name=f"slot_capacity_{s}")

for s in slots:
    model.addConstr(gp.quicksum(film_length[f] * x[f, s] for f in films) <= slot_duration[s], name=f"slot_duration_capacity_{s}")

for g in genres:
    model.addConstr(gp.quicksum(genre_ind[(f, g)] * y[f] for f in films) >= min_genre_films[g], name=f"genre_coverage_{g}")

for s in slots:
    model.addConstr(gp.quicksum(director_available[(f, s)] * x[f, s] for f in films) >= min_director_available[s], name=f"director_availability_{s}")

for f in films:
    model.addConstr(gp.quicksum(x[f, s] for s in slots) <= 1, name=f"film_assignment_unique_{f}")

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

