import gurobipy as gp
from gurobipy import GRB
import json
import csv

with open('instance.json') as f:
    instance = json.load(f)

num_drivers = instance['num_drivers']
num_trips = instance['num_trips']
num_days = instance['num_days']
num_qualifications = instance['num_qualifications']
num_depots = instance['num_depots']
num_stations = instance['num_stations']
rest_interval = instance['rest_interval']

drivers = []
with open('data/drivers.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        drivers.append(row)

trips = []
with open('data/trips.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        trips.append(row)

qualifications = []
with open('data/qualifications.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        qualifications.append(row)

stations = []
with open('data/stations.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        stations.append(row)

depots = []
with open('data/depots.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        depots.append(row)

driver_ids = [d['driver_id'] for d in drivers]
trip_ids = [t['trip_id'] for t in trips]
day_ids = list(range(num_days))
qual_ids = list(range(1, num_qualifications + 1))
depot_ids = [dp['depot_id'] for dp in depots]
station_ids = [s['station_id'] for s in stations]

model = gp.Model('driver_assignment')

assign = model.addVars(driver_ids, trip_ids, vtype=GRB.BINARY, name='assign')
deadhead = model.addVars(driver_ids, trip_ids, vtype=GRB.BINARY, name='deadhead')
overtime_hrs = model.addVars(driver_ids, vtype=GRB.INTEGER, lb=0, name='overtime_hrs')
trip_order = model.addVars(driver_ids, trip_ids, trip_ids, vtype=GRB.BINARY, name='trip_order')
day_rest = model.addVars(driver_ids, day_ids, vtype=GRB.BINARY, name='day_rest')

# Parameters from data
driver_data = {}
for d in drivers:
    did = d['driver_id']
    driver_data[did] = {
        'depot_id': d['depot_id'],
        'min_trips': int(d['min_trips']),
        'max_trips': int(d['max_trips']),
        'max_hours': int(d['max_hours']),
        'max_overtime_hrs': int(d['max_overtime_hrs']),
        'regular_pay': float(d['regular_pay']),
        'overtime_rate': float(d['overtime_rate'])
    }

trip_data = {}
for t in trips:
    tid = t['trip_id']
    trip_data[tid] = {
        'day_id': int(t['day_id']),
        'duration': int(t['duration']),
        'start_time': int(t['start_time']),
        'end_time': int(t['end_time']),
        'start_station_id': t['start_station_id'],
        'end_station_id': t['end_station_id']
    }

qual_data = {}
for q in qualifications:
    did = q['driver_id']
    qid = int(q['qualification_id'])
    val = q['has_qualification']
    if val == '1' or val == 1 or val == '祭':
        has_q = 1
    else:
        has_q = 0
    if did not in qual_data:
        qual_data[did] = {}
    qual_data[did][qid] = has_q

depot_station = {}
for dp in depots:
    depot_station[dp['depot_id']] = dp['station_id']

# Objective: minimize total cost
obj = gp.LinExpr()
for d in driver_ids:
    for t in trip_ids:
        obj += driver_data[d]['regular_pay'] * assign[d, t]
    obj += driver_data[d]['overtime_rate'] * overtime_hrs[d]
    for t in trip_ids:
        obj += 0 * deadhead[d, t]  # deadhead cost not provided, set to 0
model.setObjective(obj, GRB.MINIMIZE)

# Constraint: each trip assigned to exactly one driver
for t in trip_ids:
    model.addConstr(gp.quicksum(assign[d, t] for d in driver_ids) == 1, name=f'trip_coverage_{t}')

# Constraint: driver must have qualification for trip (simplified: assume all drivers qualified for all trips since no trip-qualification data)
# Skipping qualification_match due to missing trip_qualification data

# Constraint: min trips per driver
for d in driver_ids:
    model.addConstr(gp.quicksum(assign[d, t] for t in trip_ids) >= driver_data[d]['min_trips'], name=f'min_trips_{d}')

# Constraint: max trips per driver
for d in driver_ids:
    model.addConstr(gp.quicksum(assign[d, t] for t in trip_ids) <= driver_data[d]['max_trips'], name=f'max_trips_{d}')

# Constraint: total hours limit
for d in driver_ids:
    model.addConstr(gp.quicksum(trip_data[t]['duration'] * assign[d, t] for t in trip_ids) + overtime_hrs[d] <= driver_data[d]['max_hours'], name=f'total_hours_{d}')

# Constraint: overtime limit
for d in driver_ids:
    model.addConstr(overtime_hrs[d] <= driver_data[d]['max_overtime_hrs'], name=f'overtime_limit_{d}')

# Constraint: at least one rest day per driver
for d in driver_ids:
    model.addConstr(gp.quicksum(day_rest[d, day] for day in day_ids) >= 1, name=f'rest_day_weekly_{d}')

# Constraint: no trips on rest day
for d in driver_ids:
    for day in day_ids:
        trips_on_day = [t for t in trip_ids if trip_data[t]['day_id'] == day]
        if trips_on_day:
            model.addConstr(gp.quicksum(assign[d, t] for t in trips_on_day) <= driver_data[d]['max_trips'] * (1 - day_rest[d, day]), name=f'rest_day_link_{d}_{day}')

# Constraint: trip order consistency (outgoing)
for d in driver_ids:
    for t in trip_ids:
        model.addConstr(gp.quicksum(trip_order[d, t, t2] for t2 in trip_ids) <= assign[d, t], name=f'trip_ordering_out_{d}_{t}')

# Constraint: trip order consistency (incoming)
for d in driver_ids:
    for t in trip_ids:
        model.addConstr(gp.quicksum(trip_order[d, t1, t] for t1 in trip_ids) <= assign[d, t], name=f'trip_ordering_in_{d}_{t}')

# Constraint: minimum rest between consecutive trips (simplified: no deadhead_time data, use 0)
for d in driver_ids:
    for t1 in trip_ids:
        for t2 in trip_ids:
            if t1 != t2:
                model.addConstr(trip_order[d, t1, t2] * (trip_data[t1]['end_time'] + 0 + rest_interval) <= trip_data[t2]['start_time'] + driver_data[d]['max_trips'] * (1 - trip_order[d, t1, t2]), name=f'rest_between_{d}_{t1}_{t2}')

# Constraint: deadhead only if not assigned
for d in driver_ids:
    for t in trip_ids:
        model.addConstr(deadhead[d, t] <= 1 - assign[d, t], name=f'deadhead_only_if_unassigned_{d}_{t}')

# Constraint: deadhead only if trip starts at driver's depot station
for d in driver_ids:
    depot_id = driver_data[d]['depot_id']
    depot_st = depot_station[depot_id]
    for t in trip_ids:
        if trip_data[t]['start_station_id'] == depot_st:
            model.addConstr(deadhead[d, t] <= 1, name=f'deadhead_start_link_{d}_{t}')
        else:
            model.addConstr(deadhead[d, t] <= 0, name=f'deadhead_start_link_{d}_{t}')

# Constraint: deadhead only if trip ends at driver's depot station
for d in driver_ids:
    depot_id = driver_data[d]['depot_id']
    depot_st = depot_station[depot_id]
    for t in trip_ids:
        if trip_data[t]['end_station_id'] == depot_st:
            model.addConstr(deadhead[d, t] <= 1, name=f'deadhead_end_link_{d}_{t}')
        else:
            model.addConstr(deadhead[d, t] <= 0, name=f'deadhead_end_link_{d}_{t}')

import os
os.makedirs('output', exist_ok=True)
model.write('output/model.lp')

