import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

DEPOTS = data["DEPOTS"]
HUBS = data["HUBS"]
ZONES = data["ZONES"]
VEHICLES = data["VEHICLES"]
PERIODS = data["PERIODS"]
ROUTES = data["ROUTES"]

trans_cost = data["trans_cost"]
handling_cost = data["handling_cost"]
inv_cost = data["inv_cost"]
penalty = data["penalty"]
supply = data["supply"]
demand = data["demand"]
hub_capacity = data["hub_capacity"]
depot_capacity = data["depot_capacity"]
vehicle_capacity = data["vehicle_capacity"]
max_route_flow = data["max_route_flow"]
init_inv = data["init_inv"]
min_service = data["min_service"]
flow_time = data["flow_time"]
hub_handling_limit = data["hub_handling_limit"]
depot_throughput = data["depot_throughput"]
zone_acceptance = data["zone_acceptance"]

model = gp.Model("cross_dock_network")

flow = {}
for d in DEPOTS:
    for h in HUBS:
        for z in ZONES:
            for v in VEHICLES:
                for t in PERIODS:
                    flow[d, h, z, v, t] = model.addVar(lb=0, vtype=GRB.INTEGER, name=f"flow_{d}_{h}_{z}_{v}_{t}")

handled = {}
for h in HUBS:
    for t in PERIODS:
        handled[h, t] = model.addVar(lb=0, vtype=GRB.INTEGER, name=f"handled_{h}_{t}")

inv = {}
for d in DEPOTS:
    for t in PERIODS:
        inv[d, t] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"inv_{d}_{t}")

short = {}
for z in ZONES:
    for t in PERIODS:
        short[z, t] = model.addVar(lb=0, vtype=GRB.CONTINUOUS, name=f"short_{z}_{t}")

transit = {}
for d in DEPOTS:
    for h in HUBS:
        for z in ZONES:
            for v in VEHICLES:
                for t in PERIODS:
                    transit[d, h, z, v, t] = model.addVar(lb=0, vtype=GRB.INTEGER, name=f"transit_{d}_{h}_{z}_{v}_{t}")

obj = gp.QuadExpr()
for d in DEPOTS:
    for h in HUBS:
        for z in ZONES:
            for v in VEHICLES:
                for t in PERIODS:
                    obj += trans_cost[d][h][z][v] * flow[d, h, z, v, t]
for h in HUBS:
    for t in PERIODS:
        obj += handling_cost[h][str(t)] * handled[h, t]
for d in DEPOTS:
    for t in PERIODS:
        obj += inv_cost[d][str(t)] * inv[d, t]
for z in ZONES:
    for t in PERIODS:
        obj += penalty[z][str(t)] * short[z, t]

model.setObjective(obj, GRB.MINIMIZE)

for d in DEPOTS:
    for t in PERIODS:
        lhs = inv[d, t]
        if t == 1:
            rhs = init_inv[d] + supply[d][str(t)] - gp.quicksum(flow[d, h, z, v, t] for h in HUBS for z in ZONES for v in VEHICLES) - gp.quicksum(transit[d, h, z, v, t] for h in HUBS for z in ZONES for v in VEHICLES)
        else:
            rhs = inv[d, t-1] + supply[d][str(t)] - gp.quicksum(flow[d, h, z, v, t] for h in HUBS for z in ZONES for v in VEHICLES) - gp.quicksum(transit[d, h, z, v, t] for h in HUBS for z in ZONES for v in VEHICLES)
        model.addConstr(lhs == rhs, name=f"inv_balance_{d}_{t}")

for d in DEPOTS:
    for t in PERIODS:
        model.addConstr(inv[d, t] <= depot_capacity[d][str(t)], name=f"depot_capacity_{d}_{t}")

for d in DEPOTS:
    for t in PERIODS:
        model.addConstr(gp.quicksum(flow[d, h, z, v, t] for h in HUBS for z in ZONES for v in VEHICLES) <= depot_throughput[d][str(t)], name=f"depot_throughput_{d}_{t}")

for h in HUBS:
    for t in PERIODS:
        model.addConstr(handled[h, t] == gp.quicksum(flow[d, h, z, v, t] for d in DEPOTS for z in ZONES for v in VEHICLES), name=f"hub_handling_{h}_{t}")

for h in HUBS:
    for t in PERIODS:
        model.addConstr(handled[h, t] <= hub_capacity[h][str(t)], name=f"hub_capacity_{h}_{t}")

for h in HUBS:
    model.addConstr(gp.quicksum(handled[h, t] for t in PERIODS) <= hub_handling_limit[h], name=f"hub_total_handling_{h}")

for z in ZONES:
    for t in PERIODS:
        model.addConstr(gp.quicksum(flow[d, h, z, v, t] for d in DEPOTS for h in HUBS for v in VEHICLES) + short[z, t] >= demand[z][str(t)], name=f"demand_satisfaction_{z}_{t}")

for z in ZONES:
    for t in PERIODS:
        model.addConstr(gp.quicksum(flow[d, h, z, v, t] for d in DEPOTS for h in HUBS for v in VEHICLES) >= min_service[z][str(t)] * demand[z][str(t)], name=f"min_service_{z}_{t}")

for z in ZONES:
    for t in PERIODS:
        model.addConstr(gp.quicksum(flow[d, h, z, v, t] for d in DEPOTS for h in HUBS for v in VEHICLES) <= zone_acceptance[z][str(t)], name=f"zone_acceptance_{z}_{t}")

for v in VEHICLES:
    for t in PERIODS:
        model.addConstr(gp.quicksum(flow[d, h, z, v, t] for d in DEPOTS for h in HUBS for z in ZONES) <= vehicle_capacity[v], name=f"vehicle_capacity_{v}_{t}")

for d in DEPOTS:
    for h in HUBS:
        for z in ZONES:
            for v in VEHICLES:
                for t in PERIODS:
                    model.addConstr(flow[d, h, z, v, t] <= max_route_flow[d][h][z][v], name=f"route_capacity_{d}_{h}_{z}_{v}_{t}")

for d in DEPOTS:
    for h in HUBS:
        for z in ZONES:
            for v in VEHICLES:
                for t in PERIODS:
                    ft = flow_time[d][h][z][v]
                    if t > ft:
                        model.addConstr(transit[d, h, z, v, t] == flow[d, h, z, v, t - ft], name=f"transit_definition_{d}_{h}_{z}_{v}_{t}")
                    else:
                        model.addConstr(transit[d, h, z, v, t] == 0, name=f"transit_definition_{d}_{h}_{z}_{v}_{t}")

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

