import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

crews = data["crews"]
stages = data["stages"]
timeblocks = data["timeblocks"]
revenue = data["revenue"]
crew_availability = data["crew_availability"]
stage_capacity = data["stage_capacity"]
genre_compatibility = data["genre_compatibility"]
crew_cost = data["crew_cost"]
budget = data["budget"]
max_assignments_per_crew = data["max_assignments_per_crew"]
min_crews_per_stage = data["min_crews_per_stage"]

model = gp.Model("film_studio_assignment")

x = {}
for c in crews:
    for s in stages:
        for t in timeblocks:
            x[c, s, t] = model.addVar(vtype=GRB.BINARY, name=f"x_{c}_{s}_{t}")

y = {}
for c in crews:
    y[c] = model.addVar(vtype=GRB.BINARY, name=f"y_{c}")

model.setObjective(
    gp.quicksum(revenue[c][s][t] * x[c, s, t] for c in crews for s in stages for t in timeblocks),
    GRB.MAXIMIZE
)

for c in crews:
    for t in timeblocks:
        model.addConstr(
            gp.quicksum(x[c, s, t] for s in stages) <= crew_availability[c][t],
            name=f"crew_avail_{c}_{t}"
        )

for s in stages:
    for t in timeblocks:
        model.addConstr(
            gp.quicksum(x[c, s, t] for c in crews) <= stage_capacity[s][t],
            name=f"stage_cap_{s}_{t}"
        )

for c in crews:
    for s in stages:
        for t in timeblocks:
            model.addConstr(
                x[c, s, t] <= genre_compatibility[c][s],
                name=f"genre_{c}_{s}_{t}"
            )

model.addConstr(
    gp.quicksum(crew_cost[c] * y[c] for c in crews) <= budget,
    name="budget_limit"
)

for c in crews:
    model.addConstr(
        gp.quicksum(x[c, s, t] for s in stages for t in timeblocks) <= max_assignments_per_crew[c],
        name=f"max_assign_{c}"
    )

for s in stages:
    for t in timeblocks:
        model.addConstr(
            gp.quicksum(x[c, s, t] for c in crews) >= min_crews_per_stage[s][t],
            name=f"min_crews_{s}_{t}"
        )

for c in crews:
    total_slots = len(stages) * len(timeblocks)
    model.addConstr(
        gp.quicksum(x[c, s, t] for s in stages for t in timeblocks) <= y[c] * total_slots,
        name=f"linking_{c}"
    )

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

