import gurobipy as gp
from gurobipy import GRB
import json

with open("data.json", "r") as f:
    data = json.load(f)

depots = [d["id"] for d in data["depots"]]
outlets = [r["id"] for r in data["outlets"]]

supply = {d["id"]: d["supply"] for d in data["depots"]}
demand = {r["id"]: r["demand"] for r in data["outlets"]}

cost = {}
spoilage_rate = {}
route_capacity = {}
for r in data["routes"]:
    d = r["depot_id"]
    o = r["outlet_id"]
    cost[(d, o)] = r["cost"]
    spoilage_rate[(d, o)] = r["spoilage_rate"]
    route_capacity[(d, o)] = r["route_capacity"]

spoilage_penalty = data["spoilage_penalty"]

model = gp.Model("perishable_distribution")

ship = model.addVars(depots, outlets, lb=0, vtype=GRB.CONTINUOUS, name="ship")

model.setObjective(
    gp.quicksum(
        (cost[d, o] + spoilage_penalty * spoilage_rate[d, o]) * ship[d, o]
        for d in depots for o in outlets
    ),
    GRB.MINIMIZE
)

for d in depots:
    model.addConstr(
        gp.quicksum(ship[d, o] for o in outlets) <= supply[d],
        name=f"supply_limit_{d}"
    )

for o in outlets:
    model.addConstr(
        gp.quicksum(ship[d, o] for d in depots) >= demand[o],
        name=f"demand_fulfill_{o}"
    )

for d in depots:
    for o in outlets:
        model.addConstr(
            ship[d, o] <= route_capacity[d, o],
            name=f"route_cap_{d}_{o}"
        )

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")

