import json
import gurobipy as gp
from gurobipy import GRB

with open("data.json", "r") as f:
    data = json.load(f)

nurses = [n["nurse_id"] for n in data["NURSES"]]
wards = [w["ward_id"] for w in data["WARDS"]]
timeslots = [t["slot_id"] for t in data["TIMESLOTS"]]
shifts = [s["shift_id"] for s in data["SHIFTS"]]

max_shifts = {n["nurse_id"]: n["max_shifts"] for n in data["NURSES"]}
max_overtime = {n["nurse_id"]: n["max_overtime"] for n in data["NURSES"]}

shift_start = {s["shift_id"]: s["start"] for s in data["SHIFTS"]}
shift_end = {s["shift_id"]: s["end"] for s in data["SHIFTS"]}
shift_ward = {s["shift_id"]: s["ward_id"] for s in data["SHIFTS"]}
cost = {s["shift_id"]: s["cost"] for s in data["SHIFTS"]}

demand = {(d["ward_id"], d["slot_id"]): d["value"] for d in data["demand"]}
penalty = {(p["ward_id"], p["slot_id"]): p["value"] for p in data["penalty"]}
compatibility = {(c["nurse_id"], c["ward_id"]): c["flag"] for c in data["compatibility"]}

slot_order = {t: i for i, t in enumerate(timeslots)}

def covers(s, t):
    return slot_order[shift_start[s]] <= slot_order[t] <= slot_order[shift_end[s]]

model = gp.Model("nurse_scheduling")

x = {}
for n in nurses:
    for s in shifts:
        x[n, s] = model.addVar(vtype=GRB.INTEGER, lb=0, ub=1, name=f"x_{n}_{s}")

u = {}
for w in wards:
    for t in timeslots:
        u[w, t] = model.addVar(vtype=GRB.INTEGER, lb=0, name=f"u_{w}_{t}")

model.setObjective(
    gp.quicksum(cost[s] * x[n, s] for n in nurses for s in shifts) +
    gp.quicksum(penalty[w, t] * u[w, t] for w in wards for t in timeslots),
    GRB.MINIMIZE
)

for w in wards:
    for t in timeslots:
        model.addConstr(
            gp.quicksum(compatibility.get((n, w), 0) * x[n, s]
                        for n in nurses for s in shifts
                        if shift_ward[s] == w and covers(s, t)) + u[w, t] >= demand[w, t],
            name=f"DemandCoverage_{w}_{t}"
        )

for n in nurses:
    model.addConstr(
        gp.quicksum(x[n, s] for s in shifts) <= max_shifts[n],
        name=f"MaxShifts_{n}"
    )

for n in nurses:
    model.addConstr(
        gp.quicksum((slot_order[shift_end[s]] - slot_order[shift_start[s]]) * x[n, s] for s in shifts) <= max_overtime[n],
        name=f"OvertimeLimit_{n}"
    )

for n in nurses:
    for s in shifts:
        model.addConstr(
            x[n, s] <= compatibility.get((n, shift_ward[s]), 0),
            name=f"WardCompatibility_{n}_{s}"
        )

for n in nurses:
    for t in timeslots:
        model.addConstr(
            gp.quicksum(x[n, s] for s in shifts if covers(s, t)) <= 1,
            name=f"ShiftFlow_{n}_{t}"
        )

model.optimize()

if model.Status == GRB.OPTIMAL:
    print(f"optimal_value = {model.ObjVal}")
elif model.Status == GRB.INFEASIBLE:
    print("optimal_value = INFEASIBLE")
elif model.Status == GRB.UNBOUNDED:
    print("optimal_value = UNBOUNDED")
else:
    print("optimal_value = ERROR")
